INSERT INTO bilan_packages
  (cancer_type_id, cancer_nom, sous_type, phase, analyses_obl, analyses_opt, note_clinique)
VALUES
  (1,'Cancer du Poumon','NSCLC — Adénocarcinome','initial',$$["📡 Radiographie thorax face+profil", "🧪 NFS complète", "🧪 Bilan hépatique (ASAT/ALAT/PAL/GGT)", "🧪 LDH", "🧪 Créatinine + Clairance"]$$,$$["📡 Scanner thoracique si radio anormale"]$$,'Premier contact : confirmer présence de lésion pulmonaire avant orientation spécialisée'),
  (1,'Cancer du Poumon','NSCLC — Adénocarcinome','confirmation',$$["📡 Scanner thoracique avec injection", "🔬 Bronchoscopie + Biopsie bronchique", "🔬 IHC : TTF-1, Napsin-A, p40, CK7", "🔬 Cytologie LBA (lavage broncho-alvéolaire)"]$$,$$["🔬 Biopsie scanno-guidée si lésion périphérique", "🔬 Médiastinoscopie si ADP médiastinales"]$$,'Objectif : confirmer le diagnostic histologique et déterminer NSCLC vs SCLC puis sous-type'),
  (1,'Cancer du Poumon','NSCLC — Adénocarcinome','extension',$$["📡 Scanner TAP (thorax-abdomen-pelvis)", "📡 IRM cérébrale avec injection", "🔬 PCR EGFR (exons 18-21)", "🔬 FISH ALK / ROS1", "🔬 PCR BRAF V600E", "🔬 PCR KRAS G12C", "🔬 IHC PDL1 (score TPS)", "🧪 Cyfra 21-1 (J0)", "🧪 CEA (J0)"]$$,$$["📡 PET-Scan FDG si résécable", "🔬 NGS panel étendu (NTRK/MET/RET/HER2)", "🧪 ctDNA (biopsie liquide) si biopsie insuffisante"]$$,'CRITIQUE : PCR/FISH obligatoires avant tout traitement — déterminent la thérapie ciblée'),
  (1,'Cancer du Poumon','NSCLC — Adénocarcinome','suivi',$$["🧪 NFS (avant chaque cycle)", "🧪 Bilan hépatique (avant chaque cycle)", "🧪 Créatinine (avant chaque cycle)", "🧪 Cyfra 21-1", "🧪 CEA", "📡 Scanner TAP (tous les 2-3 cycles = 6-9 semaines)"]$$,$$["📡 IRM cérébrale (si symptômes neurologiques)", "🔬 Rebiopsie + NGS (si progression — recherche résistance T790M/C797S)", "🧪 ctDNA (suivi moléculaire)"]$$,'Évaluation RECIST 1.1 — surveillance toxicité et réponse thérapeutique'),
  (2,'Cancer du Poumon','NSCLC — Carcinome épidermoïde','initial',$$["📡 Radiographie thorax", "🧪 NFS", "🧪 Bilan hépatique", "🧪 LDH", "🧪 Créatinine"]$$,$$["📡 Scanner thoracique si masse hilaire"]$$,'Masse hilaire fréquente — souvent détectée sur radio standard'),
  (2,'Cancer du Poumon','NSCLC — Carcinome épidermoïde','confirmation',$$["📡 Scanner thoracique", "🔬 Bronchoscopie + Biopsie endobronchique", "🔬 IHC : p40, CK5/6, TTF-1 (négatif)", "🔬 Cytologie brossage bronchique"]$$,$$["🔬 EBUS (échographie endobronchique) si ADP", "🔬 Biopsie scanno-guidée si périphérique"]$$,'Le carcinome épidermoïde est souvent central — bronchoscopie en première intention'),
  (2,'Cancer du Poumon','NSCLC — Carcinome épidermoïde','extension',$$["📡 Scanner TAP", "📡 IRM cérébrale", "🔬 IHC PDL1 (score TPS) +++", "🧪 Cyfra 21-1 (J0)", "🧪 SCC", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan FDG", "🔬 PCR FGFR1 (amplifié dans 20%)", "🔬 NGS si PDL1 bas"]$$,'PDL1 crucial — si >50% : pembrolizumab en 1ère ligne sans chimio. PCR moins rentable que adéno'),
  (2,'Cancer du Poumon','NSCLC — Carcinome épidermoïde','suivi',$$["🧪 NFS (avant chaque cycle)", "🧪 Bilan hépatique + rénal", "🧪 Cyfra 21-1", "📡 Scanner TAP (tous les 2-3 cycles)"]$$,$$["📡 IRM cérébrale (si symptômes)", "🧪 SCC"]$$,'Surveillance standard — attention toxicité rénale si cisplatine'),
  (3,'Cancer du Poumon','SCLC — Carcinome à petites cellules','initial',$$["📡 Radiographie thorax", "🧪 NFS", "🧪 LDH +++", "🧪 NSE +++", "🧪 Bilan hépatique", "🧪 Natrémie (SIADH fréquent)"]$$,NULL,'NSE et LDH élevés sont très évocateurs de SCLC — orientation rapide urgente'),
  (3,'Cancer du Poumon','SCLC — Carcinome à petites cellules','confirmation',$$["📡 Scanner thoracique", "🔬 Bronchoscopie + Biopsie", "🔬 IHC : CD56, Synaptophysine, Chromogranine A, TTF-1, Ki67 (>70%)"]$$,$$["🔬 Cytologie crachat ou LBA", "🔬 Biopsie scanno-guidée"]$$,'Ki67 très élevé (>70%) caractéristique du SCLC — confirme l''agressivité'),
  (3,'Cancer du Poumon','SCLC — Carcinome à petites cellules','extension',$$["📡 Scanner TAP", "📡 IRM cérébrale URGENTE +++", "🔬 Myélogramme (si cytopénies)", "🧪 NSE (J0)", "🧪 Pro-GRP (J0)", "🧪 LDH (J0)", "🧪 Natrémie"]$$,$$["📡 PET-Scan FDG", "📡 Scintigraphie osseuse"]$$,'IRM cérébrale URGENTE — métastases cérébrales présentes dès le début dans 10-15% des cas'),
  (3,'Cancer du Poumon','SCLC — Carcinome à petites cellules','suivi',$$["🧪 NSE (avant chaque cycle — marqueur de réponse fiable)", "🧪 Pro-GRP", "🧪 LDH", "🧪 NFS", "🧪 Bilan hépatique + rénal", "📡 Scanner TAP (tous les 2 cycles)", "📡 IRM cérébrale (tous les 3 mois)"]$$,NULL,'NSE = marqueur de suivi clé pour SCLC. IRM cérébrale régulière même sous traitement'),
  (4,'Cancer du Sein','Carcinome canalaire invasif','initial',$$["📡 Mammographie bilatérale (classification BIRADS)", "📡 Échographie mammaire + axillaire", "🧪 NFS", "🧪 Bilan hépatique", "🧪 CA 15-3 (J0)", "🧪 ACE (J0)"]$$,$$["📡 IRM mammaire si densité élevée ou BRCA"]$$,'Mammographie + écho = bilan de 1ère intention. BIRADS 4-5 → biopsie obligatoire'),
  (4,'Cancer du Sein','Carcinome canalaire invasif','confirmation',$$["🔬 Core biopsie écho-guidée +++", "🔬 IHC : RE (score Allred)", "🔬 IHC : RP (score Allred)", "🔬 IHC : HER2 (score 0-3+)", "🔬 IHC : Ki67 (%)", "🔬 FISH HER2 si score IHC 2+"]$$,$$["🔬 Biopsie ganglion sentinelle axillaire", "🔬 PCR Oncotype DX (si RE+/HER2-/N0)"]$$,'IHC des 4 marqueurs OBLIGATOIRE — définit le sous-type moléculaire et le traitement'),
  (4,'Cancer du Sein','Carcinome canalaire invasif','extension',$$["📡 Scanner TAP", "📡 Scintigraphie osseuse", "🧪 CA 15-3", "🧪 ACE", "🧪 PAL (phosphatase alcaline)", "🧪 Calcémie"]$$,$$["📡 PET-Scan FDG (si stade III-IV)", "📡 IRM hépatique (si métastases hépatiques suspectées)", "🔬 Biopsie métastase (si changement traitement)"]$$,'Bilan d''extension complet uniquement si stade II-III. Stade I : scanner TAP suffit'),
  (4,'Cancer du Sein','Carcinome canalaire invasif','suivi',$$["🧪 NFS (avant chaque cycle chimio)", "🧪 Bilan hépatique", "🧪 CA 15-3", "🧪 ACE", "📡 Mammographie annuelle (sein controlatéral)"]$$,$$["📡 Écho cardiaque (si Herceptin — fraction éjection tous les 3 mois)", "📡 Scanner TAP (si progression suspectée)", "🔬 Biopsie de rechute si métastases"]$$,'Sous Herceptin : FEVG obligatoire tous les 3 mois. CA 15-3 = marqueur de suivi principal'),
  (5,'Cancer du Sein','Carcinome lobulaire invasif','initial',$$["📡 Mammographie bilatérale", "📡 Échographie mammaire bilatérale +++", "📡 IRM mammaire (sensibilité supérieure pour lobulaire)", "🧪 NFS", "🧪 CA 15-3"]$$,NULL,'IRM mammaire dès le départ pour lobulaire — mammographie souvent faussement rassurante'),
  (5,'Cancer du Sein','Carcinome lobulaire invasif','confirmation',$$["🔬 Core biopsie", "🔬 IHC : RE, RP, HER2, Ki67", "🔬 IHC : E-Cadhérine (négatif = lobulaire ++)", "🔬 FISH HER2 si score 2+"]$$,$$["🔬 PCR CDH1 (mutation germinale si bilatéral)"]$$,'E-Cadhérine négative confirme le sous-type lobulaire. Souvent RE+/PR+/HER2-'),
  (5,'Cancer du Sein','Carcinome lobulaire invasif','extension',$$["📡 Scanner TAP", "📡 Scintigraphie osseuse", "📡 IRM abdominale (métas péritonéales fréquentes)", "🧪 CA 15-3", "🧪 ACE"]$$,$$["📡 PET-Scan"]$$,'Métastases péritonéales et méningées plus fréquentes que dans le canalaire — IRM abdominale importante'),
  (5,'Cancer du Sein','Carcinome lobulaire invasif','suivi',$$["🧪 NFS", "🧪 CA 15-3", "🧪 ACE", "📡 Mammographie bilatérale annuelle", "📡 IRM mammaire annuelle"]$$,$$["📡 Scanner TAP (si symptômes)"]$$,'Surveillance IRM mammaire annuelle recommandée pour le lobulaire'),
  (6,'Cancer du Sein','Triple négatif (TNBC)','initial',$$["📡 Mammographie", "📡 Échographie mammaire + axillaire", "🧪 NFS", "🧪 Bilan hépatique"]$$,$$["📡 IRM mammaire"]$$,'Femmes jeunes souvent — masse à croissance rapide'),
  (6,'Cancer du Sein','Triple négatif (TNBC)','confirmation',$$["🔬 Core biopsie", "🔬 IHC : RE (négatif <1%)", "🔬 IHC : RP (négatif <1%)", "🔬 IHC : HER2 (score 0-1+)", "🔬 IHC : Ki67 (très élevé >30%)", "🔬 IHC : PDL1 (CPS score — pour pembrolizumab)", "🔬 BRCA1/2 (test génétique constitutionnel)"]$$,$$["🔬 NGS tumoral (BRCA somatique si constitutionnel négatif)", "🔬 IHC : TROP-2 (pour sacituzumab)"]$$,'PDL1 et BRCA OBLIGATOIRES — déterminent pembrolizumab et olaparib en 1ère ou 2ème ligne'),
  (6,'Cancer du Sein','Triple négatif (TNBC)','extension',$$["📡 Scanner TAP", "📡 IRM cérébrale (risque métastases cérébrales élevé)", "📡 Scintigraphie osseuse", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan FDG"]$$,'Risque de métastases cérébrales plus élevé que les autres sous-types — IRM cérébrale systématique'),
  (6,'Cancer du Sein','Triple négatif (TNBC)','suivi',$$["🧪 NFS (avant chaque cycle)", "🧪 Bilan hépatique + rénal", "📡 Scanner TAP (tous les 2-3 cycles)", "📡 IRM cérébrale (tous les 3-6 mois)"]$$,$$["🔬 Rebiopsie métastase (si progression)", "🧪 ctDNA"]$$,'Surveillance cérébrale rapprochée. En cas de progression : rebiopsie pour recherche de nouvelles cibles'),
  (7,'Cancer du Côlon','Adénocarcinome colorectal','initial',$$["📡 Coloscopie totale +++", "🧪 NFS (anémie ferriprive fréquente)", "🧪 CEA (J0)", "🧪 CA 19-9 (J0)", "🧪 Bilan hépatique"]$$,$$["🧪 Fer sérique + ferritine + transferrine"]$$,'Coloscopie = examen clé — biopsie systématique de toute lésion suspecte'),
  (7,'Cancer du Côlon','Adénocarcinome colorectal','confirmation',$$["🔬 Biopsie coloscopique (pièce opératoire si résécable)", "🔬 IHC : MMR (MLH1/MSH2/MSH6/PMS2) +++", "🔬 PCR MSI (microsatellite instability)", "🔬 PCR KRAS/NRAS (exons 2-3-4)", "🔬 PCR BRAF V600E"]$$,$$["🔬 IHC HER2 (si RAS/BRAF sauvage)", "🔬 NGS panel étendu (NTRK, PIK3CA)"]$$,'KRAS/NRAS/BRAF OBLIGATOIRES avant anti-EGFR (cétuximab/panitumumab). MSI = pembrolizumab'),
  (7,'Cancer du Côlon','Adénocarcinome colorectal','extension',$$["📡 Scanner TAP +++", "📡 Écho abdominale (foie)", "🧪 CEA", "🧪 CA 19-9", "🧪 Bilan hépatique complet", "🧪 NFS + Coagulation"]$$,$$["📡 IRM hépatique (si métas hépatiques)", "📡 PET-Scan (si métas hépatiques résécables)", "📡 Laparoscopie staging (si carcinose suspectée)"]$$,'Scanner TAP = gold standard. IRM hépatique si métas hépatiques — évalue résécabilité'),
  (7,'Cancer du Côlon','Adénocarcinome colorectal','suivi',$$["🧪 CEA (tous les 3 mois × 2 ans puis tous les 6 mois)", "🧪 CA 19-9", "🧪 NFS + Bilan hépatique", "📡 Scanner TAP (tous les 6 mois × 2 ans)", "📡 Coloscopie (à 1 an puis tous les 3-5 ans)"]$$,$$["📡 IRM hépatique (si CEA montant)", "📡 PET-Scan (si récidive suspectée)"]$$,'CEA = marqueur de suivi clé. Remontée → recherche récidive immédiate'),
  (8,'Cancer du Rectum','Adénocarcinome rectal','initial',$$["📡 Rectoscopie rigide (mesure distance marge anale)", "📡 Coloscopie totale (polypes synchrones)", "🧪 NFS", "🧪 CEA (J0)", "🧪 CA 19-9 (J0)"]$$,NULL,'Mesure de la distance à la marge anale CRUCIALE pour choix chirurgical (conservation sphincter)'),
  (8,'Cancer du Rectum','Adénocarcinome rectal','confirmation',$$["🔬 Biopsie rectoscopique", "🔬 IHC : MMR (MLH1/MSH2/MSH6/PMS2)", "🔬 PCR MSI", "🔬 PCR KRAS/NRAS", "🔬 PCR BRAF V600E", "📡 IRM pelvienne haute résolution +++"]$$,$$["🔬 IHC HER2", "🔬 Écho-endoscopie rectale (stade T précoce)"]$$,'IRM pelvienne = OBLIGATOIRE pour rectum — évalue T, N, MRF (marge de résection circonférentielle)'),
  (8,'Cancer du Rectum','Adénocarcinome rectal','extension',$$["📡 Scanner TAP", "📡 IRM pelvienne +++", "🧪 CEA", "🧪 CA 19-9", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan (si métas à distance)", "📡 IRM hépatique (si métas hépatiques)"]$$,'IRM pelvienne évalue la réponse à la radio-chimio néoadjuvante — répétée avant chirurgie'),
  (8,'Cancer du Rectum','Adénocarcinome rectal','suivi',$$["🧪 CEA (tous les 3 mois)", "🧪 CA 19-9", "📡 Scanner TAP (tous les 6 mois)", "📡 IRM pelvienne (à 3 mois post-chirurgie puis annuelle)", "📡 Coloscopie (à 1 an)"]$$,$$["📡 PET-Scan (si CEA montant sans lésion visible)"]$$,'IRM pelvienne post-opératoire obligatoire — dépistage récidive locale anastomotique'),
  (9,'Cancer de la Prostate','Adénocarcinome prostatique','initial',$$["🧪 PSA total + PSA libre", "🧪 Rapport PSA libre/total", "🧪 Créatinine + ECBU", "🧪 NFS", "🧪 PAL (phosphatase alcaline)"]$$,$$["🧪 PHI (Prostate Health Index) si PSA 4-10"]$$,'PSA + TR (toucher rectal) = dépistage. PSA >4 ng/mL ou TR suspect → IRM prostatique'),
  (9,'Cancer de la Prostate','Adénocarcinome prostatique','confirmation',$$["📡 IRM prostatique multiparamétrique (PI-RADS)", "🔬 Biopsies prostatiques écho-guidées (12 carottes systématiques + ciblées si PI-RADS 4-5)", "🔬 Score de Gleason / Grade ISUP", "🔬 IHC : PSA, AMACR (P504S), p63"]$$,$$["🔬 PCR BRCA1/2 + ATM (si haut risque — thérapie PARP)", "🔬 Biomarqueur urinaire PCA3"]$$,'IRM avant biopsie OBLIGATOIRE (fusion IRM-écho). Score ISUP détermine la stratégie thérapeutique'),
  (9,'Cancer de la Prostate','Adénocarcinome prostatique','extension',$$["📡 Scintigraphie osseuse (si PSA >10 ou Gleason ≥8)", "📡 Scanner TAP", "🧪 PAL", "🧪 Calcémie", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan PSMA Gallium-68 +++ (supérieur à scinti osseuse)", "📡 IRM corps entier (si PSMA non disponible)"]$$,'PET-PSMA = gold standard pour bilan d''extension si disponible. Détecte récidive biochimique précoce'),
  (9,'Cancer de la Prostate','Adénocarcinome prostatique','suivi',$$["🧪 PSA (tous les 3-6 mois)", "🧪 Testostérone (sous hormonothérapie)", "🧪 NFS + Bilan hépatique", "🧪 Bilan lipidique (sous castration)", "🧪 Glycémie (syndrome métabolique)"]$$,$$["📡 Scintigraphie osseuse (si PSA montant)", "📡 PET-Scan PSMA (si récidive biochimique)", "🔬 Rebiopsie (si résistance à castration — CRPC)"]$$,'PSA nadir après traitement = référence. Remontée confirmée ≥0.2 ng/mL = récidive biochimique'),
  (10,'Cancer Col de l''Utérus','Carcinome épidermoïde','initial',$$["📡 Frottis cervico-vaginal (cytologie Bethesda)", "🔬 HPV génotypage (16/18/autres HR)", "📡 Colposcopie si frottis anormal", "🧪 NFS", "🧪 SCC (J0)"]$$,NULL,'Frottis + HPV = dépistage combiné. Colposcopie obligatoire si ASC-H, HSIL ou HPV 16/18'),
  (10,'Cancer Col de l''Utérus','Carcinome épidermoïde','confirmation',$$["🔬 Biopsie cervicale colposcopique (punch biopsy)", "🔬 Conisation diagnostique (si micro-invasif suspect)", "🔬 IHC : CK5/6, p63, p16 (+++), Ki67", "🔬 HPV typing complet"]$$,$$["🔬 Curetage endocervical (si lésion haute)"]$$,'p16 fortement positif = marqueur d''intégration HPV high-risk — confirme la transformation maligne'),
  (10,'Cancer Col de l''Utérus','Carcinome épidermoïde','extension',$$["📡 IRM pelvienne +++", "📡 Scanner TAP", "🧪 SCC", "🧪 NFS + Bilan rénal (uretères)", "🧪 Créatinine + Clairance"]$$,$$["📡 PET-Scan FDG (stade IB2 et plus)", "📡 UIV ou uro-TDM (compression urétérale)"]$$,'IRM pelvienne = gold standard pour évaluation locale. SCC corrèle avec le volume tumoral'),
  (10,'Cancer Col de l''Utérus','Carcinome épidermoïde','suivi',$$["🧪 SCC (tous les 3-6 mois)", "📡 IRM pelvienne (à 3 mois puis annuelle)", "📡 Scanner TAP (annuel × 3 ans)"]$$,$$["📡 PET-Scan (si SCC montant)", "🔬 Biopsie (si récidive pelvienne)"]$$,'SCC normalisé après traitement = bon pronostic. Toute remontée → imagerie urgente'),
  (11,'Cancer de l''Utérus','Carcinome endométrial','initial',$$["📡 Échographie pelvienne transvaginale (épaisseur endomètre)", "🧪 NFS", "🧪 CA 125 (J0)", "🧪 Bilan hépatique"]$$,NULL,'Échographie TV : épaisseur >4mm en post-ménopause → biopsie endométriale obligatoire'),
  (11,'Cancer de l''Utérus','Carcinome endométrial','confirmation',$$["🔬 Biopsie endométriale (pipelle de Cornier ou hystéroscopie)", "🔬 IHC : RE, RP, MMR (MLH1/MSH2/MSH6/PMS2)", "🔬 PCR MSI", "🔬 PCR POLE (exonuclease domain mutations)", "🔬 PCR TP53", "🔬 IHC : p53"]$$,$$["🔬 NGS panel (si POLE muté — excellent pronostic)"]$$,'Classification moléculaire TCGA OBLIGATOIRE (POLE/MSI/p53/NSMP) — détermine le pronostic et traitement'),
  (11,'Cancer de l''Utérus','Carcinome endométrial','extension',$$["📡 IRM pelvienne +++", "📡 Scanner TAP", "🧪 CA 125", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan (stade III-IV)"]$$,'IRM évalue l''invasion myométriale et cervicale — détermine la nécessité d''un curage ganglionnaire'),
  (11,'Cancer de l''Utérus','Carcinome endométrial','suivi',$$["🧪 CA 125 (si élevé initialement)", "📡 Scanner TAP (annuel × 3 ans)", "📡 IRM pelvienne (si symptômes)"]$$,$$["📡 PET-Scan (si récidive suspectée)"]$$,'Suivi clinique + CA 125. Récidive vaginale fréquente — examen gynécologique systématique'),
  (12,'Cancer de l''Ovaire','Carcinome épithélial ovarien','initial',$$["📡 Échographie pelvienne transvaginale", "📡 Échographie abdominale (ascite)", "🧪 CA 125 (J0) +++", "🧪 HE4", "🧪 ROMA index", "🧪 NFS + Bilan hépatique", "🧪 Bilan de coagulation"]$$,$$["📡 Scanner TAP (si CA 125 très élevé)"]$$,'CA 125 + HE4 + ROMA = trilogie diagnostique. Ascite → ponction cytologique'),
  (12,'Cancer de l''Ovaire','Carcinome épithélial ovarien','confirmation',$$["🔬 Biopsie (péritonéale ou ovarienne — peropératoire si possible)", "🔬 IHC : WT1, PAX8, CK7, p53, ER", "🔬 PCR BRCA1/2 constitutionnel +++", "🔬 HRD (Homologous Recombination Deficiency)", "🔬 PCR BRCA1/2 somatique tumoral"]$$,$$["🔬 Cytologie ascite", "🔬 NGS panel (NTRK, ATM, BRIP1)"]$$,'BRCA1/2 et HRD OBLIGATOIRES — déterminent l''utilisation des inhibiteurs PARP (olaparib/niraparib)'),
  (12,'Cancer de l''Ovaire','Carcinome épithélial ovarien','extension',$$["📡 Scanner TAP +++", "📡 IRM pelvienne", "🧪 CA 125", "🧪 HE4", "🧪 NFS + Bilan complet", "🧪 Bilan de coagulation (MTEV fréquente)"]$$,$$["📡 PET-Scan (évaluation résécabilité)", "📡 IRM hépatique (métas hépatiques)"]$$,'Scanner TAP évalue la carcinose péritonéale — score de résécabilité (Fagotti/Sugarbaker)'),
  (12,'Cancer de l''Ovaire','Carcinome épithélial ovarien','suivi',$$["🧪 CA 125 (avant chaque cure puis tous les 3 mois)", "🧪 HE4", "🧪 NFS + Bilan hépatique + rénal", "📡 Scanner TAP (tous les 3 cycles puis tous les 6 mois)"]$$,$$["📡 IRM pelvienne (si récidive pelvienne)", "📡 PET-Scan (si CA 125 montant sans lésion visible)"]$$,'CA 125 normalisé après 3 cycles = bon pronostic. Doublement du CA 125 = critère de récidive (GCIG)'),
  (13,'Cancer du Foie','Carcinome hépatocellulaire (CHC)','initial',$$["📡 Échographie hépatique +++", "🧪 AFP (alpha-fœtoprotéine) +++", "🧪 Bilan hépatique complet", "🧪 TP/TCA (bilan de coagulation)", "🧪 Sérologies VHB + VHC", "🧪 NFS"]$$,$$["🧪 PIVKA-II / DCP (si disponible)"]$$,'Dépistage semestriel écho + AFP chez tout cirrhotique. Nodule >1cm → IRM hépatique'),
  (13,'Cancer du Foie','Carcinome hépatocellulaire (CHC)','confirmation',$$["📡 IRM hépatique multiparamétrique (critères LI-RADS) +++", "📡 Scanner TAP hépatique (protocole artériel)", "🔬 Biopsie hépatique (si diagnostic incertain — LI-RADS 3)", "🔬 IHC : HepPar1, Arginase-1, GPC3, CD34 (sinusoïdes)"]$$,NULL,'LI-RADS 5 sur IRM = CHC certain → pas de biopsie nécessaire (risque d''essaimage)'),
  (13,'Cancer du Foie','Carcinome hépatocellulaire (CHC)','extension',$$["📡 Scanner TAP", "📡 IRM hépatique (résécabilité)", "🧪 AFP (J0)", "🧪 Bilan hépatique + TP", "🧪 Score de Child-Pugh (fonction hépatique)", "🧪 Score MELD"]$$,$$["📡 Artériographie hépatique (si TACE planifiée)", "📡 Scintigraphie osseuse (si douleurs osseuses)"]$$,'Score Child-Pugh OBLIGATOIRE — détermine la tolérance au traitement. Child C → soins palliatifs'),
  (13,'Cancer du Foie','Carcinome hépatocellulaire (CHC)','suivi',$$["🧪 AFP (tous les 3 mois)", "🧪 Bilan hépatique", "📡 IRM hépatique ou Scanner (tous les 3 mois)"]$$,$$["📡 Artériographie (suivi post-TACE)"]$$,'AFP = marqueur de suivi. Persistance >400 après traitement = mauvais pronostic'),
  (14,'Cancer de l''Estomac','Adénocarcinome gastrique','initial',$$["📡 FOGD (fibroscopie oeso-gastro-duodénale) +++", "🧪 NFS (anémie fréquente)", "🧪 CEA (J0)", "🧪 CA 72-4 (J0)", "🧪 CA 19-9 (J0)", "🧪 Bilan hépatique"]$$,$$["🧪 Test H. pylori (sérologie ou test respiratoire)"]$$,'FOGD = examen clé avec biopsies multiples (6 minimum) sur toute lésion suspecte'),
  (14,'Cancer de l''Estomac','Adénocarcinome gastrique','confirmation',$$["🔬 Biopsies gastriques multiples (FOGD)", "🔬 IHC : HER2 (score 0-3+) +++", "🔬 FISH HER2 si score 2+", "🔬 IHC : MMR (MLH1/MSH2/MSH6/PMS2)", "🔬 PCR MSI", "🔬 IHC : PDL1 (CPS score)", "🔬 PCR EBV (EBER)"]$$,$$["🔬 IHC CLDN18.2 (si RAS/HER2 sauvage — zolbetuximab)", "🔬 PCR FGFR2"]$$,'HER2, MSI, PDL1, EBV = 4 biomarqueurs OBLIGATOIRES — définissent les thérapies ciblées disponibles'),
  (14,'Cancer de l''Estomac','Adénocarcinome gastrique','extension',$$["📡 Scanner TAP +++", "📡 Écho-endoscopie (stade T et N local)", "🧪 CEA", "🧪 CA 72-4", "🧪 CA 19-9", "🧪 Albuminémie (dénutrition)", "🧪 NFS + Bilan complet"]$$,$$["📡 Laparoscopie de staging (carcinose péritonéale)", "📡 PET-Scan (si résécable potentiel)"]$$,'Laparoscopie de staging RECOMMANDÉE avant résection — exclut carcinose occulte non visible au scanner'),
  (14,'Cancer de l''Estomac','Adénocarcinome gastrique','suivi',$$["🧪 CEA (tous les 3 mois)", "🧪 CA 72-4", "🧪 NFS + Bilan hépatique", "🧪 Albuminémie + Vitamines B12 (post-gastrectomie)", "📡 Scanner TAP (tous les 6 mois × 2 ans)", "📡 FOGD (annuelle)"]$$,$$["📡 PET-Scan (si CEA montant)"]$$,'Post-gastrectomie : supplémentation B12 mensuelle à vie. CA 72-4 = marqueur le plus spécifique'),
  (15,'Cancer du Pancréas','Adénocarcinome pancréatique','initial',$$["📡 Échographie abdominale", "🧪 CA 19-9 +++", "🧪 CEA", "🧪 Bilan hépatique (ictère)", "🧪 Bilirubine totale + directe", "🧪 Amylase + Lipase", "🧪 Glycémie + HbA1c"]$$,NULL,'CA 19-9 élevé + ictère + masse pancréatique = triade diagnostique. Urgence diagnostique'),
  (15,'Cancer du Pancréas','Adénocarcinome pancréatique','confirmation',$$["📡 Scanner TAP protocole pancréas (triphasique) +++", "📡 IRM avec bili-IRM (Wirsungographie)", "🔬 Écho-endoscopie + cytoponction (FNA)", "🔬 IHC : CK7, CK19, MUC1, MUC4, CA19-9, CEA", "🔬 PCR KRAS (muté >90%)", "🔬 Bilan génétique : BRCA2, PALB2, ATM"]$$,$$["🔬 Cytoponction scanno-guidée (si EUS impossible)", "🔬 ERCP + biopsie canalaire"]$$,'KRAS muté = quasi-pathognomonique. BRCA2/PALB2/ATM → olaparib en maintenance'),
  (15,'Cancer du Pancréas','Adénocarcinome pancréatique','extension',$$["📡 Scanner TAP (résécabilité artères)", "🧪 CA 19-9", "🧪 CEA", "🧪 Bilan hépatique", "🧪 Albuminémie (dénutrition sévère fréquente)", "🧪 NFS + Coagulation"]$$,$$["📡 PET-Scan (si résécable borderline)", "📡 Laparoscopie de staging", "📡 Artériographie mésentérique (si résection vasculaire)"]$$,'Évaluation résécabilité artérielle (AMS/TC) au scanner OBLIGATOIRE — détermine la chirurgie'),
  (15,'Cancer du Pancréas','Adénocarcinome pancréatique','suivi',$$["🧪 CA 19-9 (tous les 3 mois)", "🧪 CEA", "🧪 Bilan hépatique", "🧪 Albuminémie", "🧪 NFS", "📡 Scanner TAP (tous les 3 mois)"]$$,$$["📡 IRM (si métas hépatiques)"]$$,'CA 19-9 = seul marqueur fiable. Attention : faussement négatif si groupe sanguin Lewis a-b-'),
  (16,'Cancer Thyroïde','Carcinome papillaire','initial',$$["📡 Échographie thyroïdienne (TIRADS) +++", "🧪 TSH", "🧪 T3 + T4 libres", "🧪 Calcitonine (éliminer médullaire)", "🧪 Calcémie"]$$,$$["🧪 Anti-TPO + Anti-Tg (thyroïdite associée)"]$$,'TIRADS 4-5 → cytoponction obligatoire. Calcitonine systématique avant biopsie'),
  (16,'Cancer Thyroïde','Carcinome papillaire','confirmation',$$["🔬 Cytoponction thyroïdienne écho-guidée (FNA) — classification Bethesda", "🔬 IHC : CK19, HBME-1, Galectine-3, CD56 (négatif papillaire)", "🔬 PCR BRAF V600E +++", "🔬 PCR RAS, RET/PTC (fusion)"]$$,$$["🔬 Bethesda III-V → chirurgie sans attendre moléculaire"]$$,'BRAF V600E muté dans 60% des papillaires — facteur de risque de récidive. Influence la chirurgie'),
  (16,'Cancer Thyroïde','Carcinome papillaire','extension',$$["📡 Échographie cervicale complète (ganglions)", "📡 Scanner cervico-thoracique (sans iode — avant iode radioactif)", "🧪 Thyroglobuline (J0 — baseline pré-opératoire)", "🧪 Anti-Tg", "🧪 TSH", "🧪 Calcémie"]$$,$$["📡 Scintigraphie corps entier (post-thyroïdectomie)"]$$,'Scanner SANS injection iodée OBLIGATOIRE si iode radioactif planifié — l''iode sature les récepteurs'),
  (16,'Cancer Thyroïde','Carcinome papillaire','suivi',$$["🧪 Thyroglobuline (sous TSH stimulée ou rhTSH) +++", "🧪 Anti-Tg (si Tg indétectable)", "🧪 TSH (cible selon risque : 0.1-0.5 ou 0.5-2)", "📡 Échographie cervicale (annuelle)"]$$,$$["📡 Scintigraphie corps entier (si Tg montante)", "📡 PET-Scan FDG (si Tg élevée + scinti négative — dédifférenciation)"]$$,'Thyroglobuline = marqueur de suivi gold standard. Tg indétectable sous suppression = rémission'),
  (17,'Cancer Thyroïde','Carcinome anaplasique','initial',$$["📡 Échographie cervicale URGENTE", "📡 Scanner cervico-thoracique URGENT", "🧪 TSH + T3/T4", "🧪 LDH", "🧪 CRP", "🧪 NFS"]$$,NULL,'URGENCE ABSOLUE — croissance en jours. Scanner en urgence pour évaluer compression trachéale'),
  (17,'Cancer Thyroïde','Carcinome anaplasique','confirmation',$$["🔬 Biopsie chirurgicale ou Tru-Cut URGENTE", "🔬 IHC : CK (focale), Vimentine, p53, TTF-1 (négatif)", "🔬 PCR BRAF V600E (dabrafénib si muté)", "🔬 PCR ALK, RET, NTRK"]$$,$$["🔬 NGS panel étendu (thérapie ciblée ultime recours)"]$$,'PCR BRAF URGENTE — dabrafénib + tramétinib si BRAF muté = seule chance thérapeutique ciblée'),
  (17,'Cancer Thyroïde','Carcinome anaplasique','extension',$$["📡 Scanner TAP URGENT", "📡 IRM cervicale (extension locale)", "🧪 LDH", "🧪 CRP", "🧪 Calcémie", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan FDG"]$$,'Bilan en 48-72h maximum — survie médiane <6 mois. Décision thérapeutique en extrême urgence'),
  (17,'Cancer Thyroïde','Carcinome anaplasique','suivi',$$["📡 Scanner TAP (tous les 6-8 semaines)", "🧪 LDH", "🧪 CRP", "🧪 NFS"]$$,NULL,'Suivi rapproché — réévaluation fréquente. Soins palliatifs à intégrer dès le début'),
  (18,'Cancer de la Vessie','Carcinome urothélial','initial',$$["📡 Échographie vésicale (résidu post-mictionnel)", "🧪 Cytologie urinaire +++", "🧪 NFS", "🧪 Créatinine + Clairance", "🧪 ECBU (éliminer infection)"]$$,$$["🧪 NMP22 (BladderChek)", "🧪 UroVysion FISH urinaire"]$$,'Hématurie macroscopique → cytologie + échographie + cystoscopie. Urgence diagnostique'),
  (18,'Cancer de la Vessie','Carcinome urothélial','confirmation',$$["📡 Cystoscopie blanche + fluorescence (Hexvix) +++", "🔬 RTUV (résection transurétrale de vessie)", "🔬 IHC : CK7, CK20, GATA3, Uroplakin", "🔬 IHC : PDL1 (si musculo-invasif)", "🔬 PCR FGFR3 (si superficiel — erdafitinib)"]$$,$$["🔬 NGS panel (si métastatique)", "🔬 Biopsie urètre prostatique (si tumeur col)"]$$,'RTUV = biopsie + traitement initial. Musculeuse OBLIGATOIREMENT incluse dans le fragment'),
  (18,'Cancer de la Vessie','Carcinome urothélial','extension',$$["📡 Scanner TAP (uro-TDM) +++", "📡 IRM vésicale (envahissement graisse péri-vésicale)", "🧪 Créatinine (bilatéral — urétérohydronéphrose)", "🧪 NFS", "🧪 NMP22"]$$,$$["📡 PET-Scan FDG (si musculo-invasif)", "📡 Scintigraphie osseuse (si douleurs)"]$$,'TDM détecte adénopathies et métas viscérales. IRM évalue l''envahissement local (stade T)'),
  (18,'Cancer de la Vessie','Carcinome urothélial','suivi',$$["📡 Cystoscopie (tous les 3 mois × 2 ans, puis tous les 6 mois)", "🧪 Cytologie urinaire (à chaque cystoscopie)", "🧪 Créatinine", "📡 Scanner TAP (annuel si haut risque)"]$$,$$["🧪 NMP22 (entre les cystoscopies)"]$$,'Cystoscopie de surveillance OBLIGATOIRE — haut risque de récidive locale (50-70% à 5 ans)'),
  (19,'Cancer du Rein','Carcinome à cellules claires','initial',$$["📡 Échographie rénale", "📡 Scanner TAP avec protocole rénal (triphasique)", "🧪 NFS", "🧪 Créatinine + Clairance", "🧪 LDH", "🧪 Calcémie", "🧪 NFS"]$$,NULL,'Découverte souvent fortuite sur scanner. Triade classique (hématurie+douleur+masse) = stade tardif'),
  (19,'Cancer du Rein','Carcinome à cellules claires','confirmation',$$["📡 IRM rénale (caractérisation tumorale — Bosniak)", "🔬 Biopsie rénale (si doute diagnostique ou avant traitement systémique)", "🔬 IHC : CA9 (+++), PAX8, CD10, RCC, Vimentine", "🔬 PCR VHL (délétion/mutation)"]$$,$$["🔬 FISH VHL", "🔬 Test génétique constitutionnel (si <46 ans ou bilatéral — VHL/SDHB/FH/MET)"]$$,'Biopsie si stade métastatique avant traitement systémique. IHC CA9+/PAX8+ = CCR type clair'),
  (19,'Cancer du Rein','Carcinome à cellules claires','extension',$$["📡 Scanner TAP +++", "📡 IRM cérébrale (métas cérébrales fréquentes)", "🧪 LDH +++", "🧪 Calcémie", "🧪 NFS", "🧪 Hémoglobine", "🧪 Créatinine"]$$,$$["📡 Scintigraphie osseuse (si douleurs)", "📡 PET-Scan FDG (si disponible)"]$$,'Score IMDC (pronostic) basé sur : LDH, Ca, Hb, Délai diag-ttt, Karnofsky, neutrophiles, plaquettes'),
  (19,'Cancer du Rein','Carcinome à cellules claires','suivi',$$["📡 Scanner TAP (tous les 3-6 mois)", "🧪 LDH", "🧪 Calcémie", "🧪 NFS + Bilan hépatique", "🧪 Créatinine (toxicité TKI rénale)", "🧪 TSH (toxicité thyroïdienne sous sunitinib)"]$$,$$["📡 IRM cérébrale (si symptômes neurologiques)", "📡 Scintigraphie osseuse (si douleurs)"]$$,'TSH mensuelle sous sunitinib/pazopanib. Toxicité thyroïdienne dans 50% des cas'),
  (20,'Leucémie','Leucémie lymphoblastique aiguë (LLA)','initial',$$["🧪 NFS + Frottis sanguin +++", "🧪 LDH +++", "🧪 Acide urique", "🧪 Bilan hépatique", "🧪 Bilan rénal", "🧪 Bilan de coagulation (TP/TCA/Fibrinogène)", "🧪 Groupe sanguin + RAI"]$$,NULL,'NFS + frottis = diagnostic immédiat. Blastes circulants caractéristiques. Urgence hématologique'),
  (20,'Leucémie','Leucémie lymphoblastique aiguë (LLA)','confirmation',$$["🔬 Myélogramme URGENT (frottis + biopsie)", "🔬 Immunophénotypage (cytométrie en flux) : CD19/CD10/CD34/TdT/CD3", "🔬 Caryotype +++", "🔬 PCR BCR-ABL (t9;22) — Philadelphia +++", "🔬 PCR MLL-AF4 (t4;11)", "🔬 PCR ETV6-RUNX1 (t12;21 — enfant)", "🔬 Cytologie LCR (ponction lombaire URGENTE)"]$$,$$["🔬 NGS panel complet (IKZF1, CDKN2A, JAK2)", "🔬 FISH panel LLA"]$$,'BCR-ABL positif = LLA Ph+ → imatinib/dasatinib ajouté à chimio. Ponction lombaire URGENTE (atteinte méningée)'),
  (20,'Leucémie','Leucémie lymphoblastique aiguë (LLA)','extension',$$["📡 Scanner TAP (ADP médiastinales — T-LLA)", "📡 IRM cérébrale (si PL positive)", "🧪 LDH", "🧪 Acide urique (risque lyse tumorale)", "🧪 Phosphore + Potassium + Calcium (syndrome de lyse)"]$$,$$["📡 Échographie testiculaire (garçons — sanctuaire)", "📡 Écho cardiaque (avant anthracyclines)"]$$,'Prévention syndrome de lyse OBLIGATOIRE (hyperhydratation + allopurinol/rasburicase) avant chimio'),
  (20,'Leucémie','Leucémie lymphoblastique aiguë (LLA)','suivi',$$["🔬 Myélogramme (J15, J28, fin induction, puis trimestriel)", "🔬 PCR BCR-ABL quantitative (si Ph+) +++", "🔬 MRD (Maladie Résiduelle Détectable) cytométrie", "🧪 NFS (quotidienne en aplasie)", "🧪 Hémocultures (si fièvre en aplasie)", "🧪 Bilan hépatique + rénal"]$$,$$["📡 IRM cérébrale (si symptômes SNC)", "📡 Écho cardiaque (surveillance anthracyclines)"]$$,'MRD = marqueur pronostique majeur. MRD négative à J28 = meilleur pronostic. Ph+ : PCR BCR-ABL mensuelle'),
  (21,'Leucémie','Leucémie myéloïde aiguë (LMA)','initial',$$["🧪 NFS + Frottis sanguin URGENT", "🧪 Bilan de coagulation URGENT (TP/TCA/Fibrinogène/D-Dimères — CIVD si LAM3)", "🧪 LDH", "🧪 Acide urique", "🧪 Bilan hépatique + rénal", "🧪 Groupe sanguin + RAI URGENT"]$$,NULL,'URGENCE ABSOLUE si LAM3 (M3) — CIVD potentiellement fatale. Bilan coag en extrême urgence'),
  (21,'Leucémie','Leucémie myéloïde aiguë (LMA)','confirmation',$$["🔬 Myélogramme URGENT + BOM", "🔬 Immunophénotypage : CD13/CD33/CD34/CD117/MPO", "🔬 Caryotype +++", "🔬 PCR PML-RARA (t15;17 — LAM3)", "🔬 PCR CBFB-MYH11 (inv16)", "🔬 PCR RUNX1-RUNX1T1 (t8;21)", "🔬 PCR FLT3 (ITD + TKD) +++", "🔬 PCR NPM1 +++", "🔬 PCR IDH1/IDH2", "🔬 PCR TP53, RUNX1, ASXL1"]$$,$$["🔬 NGS panel étendu LMA", "🔬 PCR WT1 (MRD)"]$$,'FLT3-ITD + NPM1 = biomarqueurs pronostiques MAJEURS. FLT3+ → midostaurin. IDH1/2 → ivosidenib/enasidenib'),
  (21,'Leucémie','Leucémie myéloïde aiguë (LMA)','extension',$$["📡 Scanner TAP", "📡 Écho cardiaque (FE avant anthracyclines)", "🧪 Syndrome de lyse (uricémie/phosphore/potassium/calcémie)", "🧪 Hémocultures (immunodépression)"]$$,$$["📡 IRM cérébrale (si neurologie)", "📡 Ponction lombaire (si signes neurologiques)"]$$,'Écho cardiaque OBLIGATOIRE avant daunorubicine — FE<50% = contre-indication anthracyclines'),
  (21,'Leucémie','Leucémie myéloïde aiguë (LMA)','suivi',$$["🔬 Myélogramme (J15, J28, fin induction, avant consolidation)", "🔬 PCR NPM1 ou FLT3 (MRD) +++", "🔬 Caryotype (si anomalie initiale)", "🧪 NFS (quotidienne en aplasie)", "🧪 Hémocultures (fièvre en aplasie — urgence)", "🧪 Galactomannane (aspergillose)", "🧪 Bilan hépatique + rénal"]$$,$$["📡 TDM thoracique (fièvre persistante — aspergillose)", "📡 Écho cardiaque (anthracyclines cumulatives)"]$$,'MRD après induction = marqueur décisionnel pour allogreffe. Aplasie profonde → antibioprophylaxie'),
  (22,'Leucémie','Leucémie myéloïde chronique (LMC)','initial',$$["🧪 NFS + Frottis sanguin (hyperleucocytose avec myélémie)", "🧪 LDH", "🧪 Acide urique", "🧪 Bilan hépatique + rénal", "🧪 Vitamine B12 (très élevée dans LMC)"]$$,NULL,'Hyperleucocytose avec toute la lignée myéloïde visible = tableau caractéristique. Urgence relative'),
  (22,'Leucémie','Leucémie myéloïde chronique (LMC)','confirmation',$$["🔬 Myélogramme + BOM", "🔬 Caryotype OBLIGATOIRE (t9;22 Chromosome Philadelphie)", "🔬 PCR BCR-ABL quantitative (IS — International Scale) +++", "🔬 FISH BCR-ABL (si caryotype négatif)", "🔬 Score de Sokal / ELTS (pronostic)"]$$,$$["🔬 PCR mutations domaine kinase ABL1 (si résistance TKI)"]$$,'Caryotype + PCR BCR-ABL = confirmation diagnostique. Score ELTS oriente vers imatinib ou TKI 2e gen'),
  (22,'Leucémie','Leucémie myéloïde chronique (LMC)','extension',$$["📡 Échographie abdominale (splénomégalie — taille rate)", "🧪 LDH", "🧪 Acide urique", "🧪 NFS complète", "🧪 Bilan hépatique (avant imatinib — métabolisme CYP3A4)"]$$,$$["📡 Écho cardiaque (si nilotinib prévu — risque CV)", "📡 Scanner TAP (si phase accélérée/blastique)"]$$,'Mesure de rate OBLIGATOIRE à J0. Nilotinib contre-indiqué si QTc prolongé → ECG avant'),
  (22,'Leucémie','Leucémie myéloïde chronique (LMC)','suivi',$$["🔬 PCR BCR-ABL quantitative (IS) — mensuel × 3 mois puis tous les 3 mois +++", "🧪 NFS (mensuel × 3 mois puis trimestriel)", "🧪 Bilan hépatique (mensuel)", "🧪 Lipase/amylase (dasatinib — épanchement pleural)"]$$,$$["📡 Échographie pleurale (dyspnée sous dasatinib)", "🔬 Caryotype (si réponse insuffisante)", "🔬 PCR mutations ABL1 (si perte de réponse)"]$$,'Réponse moléculaire majeure (RMM : BCR-ABL <0.1% IS) = objectif à 12 mois. Arrêt TKI si RMM profonde >2 ans'),
  (23,'Leucémie','Leucémie lymphoïde chronique (LLC)','initial',$$["🧪 NFS + Frottis sanguin (lymphocytose + ombres de Gümprecht)", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 Immunoglobulines (hypogammaglobulinémie)", "🧪 Test de Coombs direct (AHAI associée)"]$$,NULL,'LLC = découverte souvent fortuite sur NFS. Lymphocytose >5G/L persistent > 3 mois = critère diagnostique'),
  (23,'Leucémie','Leucémie lymphoïde chronique (LLC)','confirmation',$$["🔬 Immunophénotypage sang périphérique : CD5/CD19/CD23/CD20(faible)/CD200/ROR1", "🔬 Score de Matutes (≥4/5)", "🔬 FISH : del17p +++, del11q, trisomie 12, del13q", "🔬 PCR IGHV (muté = bon pronostic, non muté = mauvais)", "🔬 PCR TP53 (mutation) +++"]$$,$$["🔬 Biopsie ganglionnaire (si transformation Richter suspectée)"]$$,'Del17p + mutation TP53 = RÉSISTANCE à chimio-immunothérapie → venetoclax/ibrutinib d''emblée'),
  (23,'Leucémie','Leucémie lymphoïde chronique (LLC)','extension',$$["📡 Scanner TAP (si stade Binet B-C)", "📡 Échographie abdominale (rate + foie)", "🧪 Bêta-2 microglobuline", "🧪 LDH", "🧪 Bilan hépatique"]$$,$$["📡 PET-Scan (si transformation Richter suspectée — hypermétabolisme)", "🔬 Biopsie ganglionnaire (PET+ — transformation)"]$$,'Stade Binet A asymptomatique = surveillance seule (wait and watch). Traitement si Binet B-C symptomatique'),
  (23,'Leucémie','Leucémie lymphoïde chronique (LLC)','suivi',$$["🧪 NFS (tous les 3-6 mois)", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 Immunoglobulines (si infections répétées)", "📡 Scanner TAP (si progression)"]$$,$$["📡 PET-Scan (si transformation Richter)", "🔬 Rebiopsie (si transformation)"]$$,'LLC indolente : surveillance NFS tous les 3-6 mois suffit. Sous ibrutinib : surveillance hémorragie + FA'),
  (24,'Lymphome','Lymphome de Hodgkin','initial',$$["📡 Radiographie thorax (masse médiastinale)", "🧪 NFS + VS +++", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 Albumine", "🧪 Bilan hépatique"]$$,NULL,'Adénopathie cervicale indolore + masse médiastinale + sueurs nocturnes chez jeune = Hodgkin jusqu''à preuve contraire'),
  (24,'Lymphome','Lymphome de Hodgkin','confirmation',$$["🔬 Biopsie ganglionnaire CHIRURGICALE (pas FNA) +++", "🔬 IHC : CD30 +++, CD15, PAX5 (faible), CD20 (négatif)", "🔬 IHC : cellules de Reed-Sternberg", "🔬 PCR EBV (EBER in situ hybridization)"]$$,$$["🔬 Médiastinoscopie (si biopsie ganglionnaire impossible)"]$$,'Biopsie chirurgicale OBLIGATOIRE — la FNA ne suffit pas pour le diagnostic histologique du Hodgkin'),
  (24,'Lymphome','Lymphome de Hodgkin','extension',$$["📡 PET-Scan FDG +++ (stadification)", "📡 Scanner TAP (si PET non disponible)", "🔬 Myélogramme (si symptômes B + stade avancé)", "🧪 NFS", "🧪 VS", "🧪 LDH", "🧪 Albumine", "🧪 Bilan hépatique"]$$,$$["📡 IRM médiastin (si masse volumineuse)", "📡 Écho cardiaque (si RT médiastinale prévue)"]$$,'PET-Scan = gold standard pour stadification et évaluation interim (après 2 cycles = Deauville)'),
  (24,'Lymphome','Lymphome de Hodgkin','suivi',$$["📡 PET-Scan (après 2 cycles — score Deauville) +++", "📡 PET-Scan (fin traitement)", "🧪 NFS + VS", "🧪 LDH", "🧪 Bilan hépatique", "🧪 TSH (si irradiation cervicale — hypothyroïdie)"]$$,$$["📡 Écho cardiaque annuelle (si RT médiastinale)", "📡 Mammographie (femmes irradiées médiastin avant 30 ans — dépistage secondaire)"]$$,'Score de Deauville ≤3 après 2 cycles = réponse favorable. Bonne réponse PET = réduction traitement possible'),
  (25,'Lymphome','Lymphome diffus grandes cellules B (DLBCL)','initial',$$["📡 Scanner TAP (masse rapidement progressive)", "🧪 NFS", "🧪 LDH +++", "🧪 Bêta-2 microglobuline", "🧪 Bilan hépatique", "🧪 Acide urique (lyse tumorale si masse volumineuse)"]$$,NULL,'LDH très élevé + croissance rapide = urgence diagnostique. IPI score (pronostic) basé sur LDH + autres'),
  (25,'Lymphome','Lymphome diffus grandes cellules B (DLBCL)','confirmation',$$["🔬 Biopsie ganglionnaire ou tumorale +++", "🔬 IHC : CD20 +++, CD19, CD10, BCL2, BCL6, MUM1, Ki67", "🔬 Hans score (GCB vs non-GCB)", "🔬 FISH MYC +++", "🔬 FISH BCL2 +++", "🔬 FISH BCL6 (double/triple hit si MYC+BCL2/BCL6+)", "🔬 IHC PDL1 (si EBV+)", "🔬 PCR EBV"]$$,$$["🔬 NGS panel DLBCL (C5/EZB/MYD88/ABC sous-types)"]$$,'Double hit (MYC+BCL2) = HGBL → traitement intensifié (DA-EPOCH-R). IHC + FISH OBLIGATOIRES'),
  (25,'Lymphome','Lymphome diffus grandes cellules B (DLBCL)','extension',$$["📡 PET-Scan FDG +++", "📡 Scanner TAP", "🔬 Myélogramme (stade IV)", "📡 IRM cérébrale + PL (si signes SNC ou DLBCL testiculaire/rénal)", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 Bilan hépatique"]$$,$$["📡 Écho cardiaque (anthracyclines)", "📡 TEP cérébrale (si atteinte SNC)"]$$,'Atteinte SNC à rechercher si DLBCL testiculaire, rénal, mammaire ou CNS-IPI ≥4 → prophylaxie MTX'),
  (25,'Lymphome','Lymphome diffus grandes cellules B (DLBCL)','suivi',$$["📡 PET-Scan (fin traitement — score Deauville) +++", "📡 PET-Scan (après 4 cycles — interim)", "🧪 NFS + LDH (avant chaque cycle)", "🧪 Bilan hépatique", "🧪 Bilan rénal", "📡 Écho cardiaque (si anthracyclines cumulatives)"]$$,$$["📡 PET-Scan (si récidive suspectée)", "🔬 Rebiopsie (si progression — CAR-T éligibilité)"]$$,'Deauville ≤2 fin traitement = rémission complète. Rechute précoce (<12 mois) → CAR-T cells si éligible'),
  (26,'Lymphome','Lymphome folliculaire','initial',$$["📡 Scanner TAP", "🧪 NFS", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 Bilan hépatique"]$$,NULL,'Évolution lente — souvent découverte fortuite. Adénopathies diffuses indolores chez adulte d''âge moyen'),
  (26,'Lymphome','Lymphome folliculaire','confirmation',$$["🔬 Biopsie ganglionnaire chirurgicale", "🔬 IHC : CD20, CD10, BCL2 (+++), BCL6, CD23, cycline D1 (neg)", "🔬 Grade histologique (1-2 vs 3a vs 3b)", "🔬 FISH t(14;18) BCL2-IGH +++", "🔬 PCR BCL2 (MRD)"]$$,$$["🔬 NGS (EZH2 — tazémétosta si muté)"]$$,'Grade 3b = traitement comme DLBCL. FISH t(14;18) confirme le diagnostic dans 85% des cas'),
  (26,'Lymphome','Lymphome folliculaire','extension',$$["📡 PET-Scan FDG", "📡 Scanner TAP", "🔬 Myélogramme (très fréquemment envahi — 70%)", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 FLIPI score (NFS+Hb+LDH+Bêta2+Stade)"]$$,NULL,'FLIPI score OBLIGATOIRE (0-2 = bon, 3-5 = mauvais). Myélogramme positif = stade IV mais pronostic similaire'),
  (26,'Lymphome','Lymphome folliculaire','suivi',$$["📡 Scanner TAP (tous les 6 mois × 2 ans puis annuel)", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 NFS", "📡 PET-Scan (si progression clinique)"]$$,$$["🔬 Rebiopsie (si transformation Richter/DLBCL suspectée — LDH montant + hypermétabolisme)"]$$,'Surveillance active sans traitement si asymptomatique (Stade I-II, masse <7cm). Transformation = urgence'),
  (27,'Myélome Multiple','Myélome à plasmocytes','initial',$$["🧪 Électrophorèse des protéines sériques (EPS) +++", "🧪 Immunofixation sérique", "🧪 Chaînes légères libres sériques (kappa/lambda) +++", "🧪 NFS", "🧪 Créatinine", "🧪 Calcémie +++", "🧪 LDH", "🧪 Bêta-2 microglobuline", "🧪 Albumine"]$$,$$["🧪 Immunofixation urinaire sur urine 24h (Bence-Jones)"]$$,'Triade CRAB : Calcium élevé / Rein atteint / Anémie / os (Bones) = critères de traitement'),
  (27,'Myélome Multiple','Myélome à plasmocytes','confirmation',$$["🔬 Myélogramme (≥10% plasmocytes) +++", "🔬 Biopsie ostéo-médullaire (BOM)", "🔬 IHC : CD138, CD38, CD56, CD19, CD45, Kappa/Lambda (restriction clonale)", "🔬 FISH : del(17p13) +++, t(4;14), t(14;16), t(11;14), gain 1q21", "🔬 PCR TP53"]$$,$$["🔬 NGS panel myélome"]$$,'Del17p et t(4;14) = haut risque cytogénétique → traitement intensifié. t(11;14) → venetoclax possible'),
  (27,'Myélome Multiple','Myélome à plasmocytes','extension',$$["📡 Body scanner faible dose (squelette entier) +++", "📡 IRM rachis (compression médullaire)", "📡 IRM corps entier (si body scanner négatif)", "🧪 Calcémie", "🧪 Créatinine", "🧪 NFS", "🧪 Pic M (quantification)"]$$,$$["📡 PET-Scan FDG (plasmocytome extra-médullaire)", "📡 Radiographies osseuses standard (si body scanner impossible)"]$$,'IRM rachis URGENTE si douleurs dorsales ou déficit neurologique — compression médullaire = urgence chirurgicale'),
  (27,'Myélome Multiple','Myélome à plasmocytes','suivi',$$["🧪 Chaînes légères libres kappa/lambda +++", "🧪 EPS + Immunofixation (tous les 3 mois)", "🧪 Pic M (quantification)", "🧪 NFS + Créatinine", "🧪 Calcémie", "📡 IRM rachis (si douleurs)"]$$,$$["📡 PET-Scan (si progression clinique)", "🔬 Myélogramme (si critères de rechute)"]$$,'Critères de réponse IMWG : RC (immunofixation négative) = objectif optimal. CLLs = marqueur le plus sensible'),
  (28,'Mélanome','Mélanome malin cutané','initial',$$["📡 Dermoscopie numérique +++", "🧪 NFS", "🧪 LDH +++", "🧪 S100-B (J0)", "🧪 Bilan hépatique"]$$,NULL,'Dermoscopie = examen clé. Critères ABCDE ou score de Glasgow. Toute lésion suspecte → biopsie-exérèse complète'),
  (28,'Mélanome','Mélanome malin cutané','confirmation',$$["🔬 Biopsie-exérèse complète (pas biopsie partielle) +++", "🔬 IHC : S100, HMB-45, Melan-A/MART-1, SOX10, Ki67", "🔬 Indice de Breslow (épaisseur mm) +++", "🔬 Présence ulcération + mitoses", "🔬 PCR BRAF V600E +++ (60% des mélanomes)", "🔬 PCR NRAS", "🔬 PCR c-KIT (mélanomes muqueux/acral)"]$$,$$["🔬 NGS panel étendu (NTRK, NF1, GNAQ/GNA11 — uvéal)"]$$,'Breslow = facteur pronostique #1. BRAF V600E muté → dabrafénib+tramétinib ou vémurafénib+cobimétinib'),
  (28,'Mélanome','Mélanome malin cutané','extension',$$["📡 Scanner TAP +++", "📡 IRM cérébrale +++", "📡 PET-Scan FDG (si stade IIB+)", "🔬 Ganglion sentinelle (Breslow ≥0.8mm)", "🧪 LDH", "🧪 S100-B", "🧪 NFS + Bilan complet"]$$,$$["📡 Échographie ganglionnaire régionale"]$$,'Ganglion sentinelle OBLIGATOIRE si Breslow ≥0.8mm ou <0.8mm avec ulcération. IRM cérébrale systématique stade III-IV'),
  (28,'Mélanome','Mélanome malin cutané','suivi',$$["🧪 LDH (tous les 3 mois)", "🧪 S100-B", "📡 Scanner TAP (tous les 3-6 mois)", "📡 IRM cérébrale (tous les 6 mois)", "📡 Dermoscopie (surveillance cutanée)"]$$,$$["📡 PET-Scan (si progression suspectée)", "🔬 Rebiopsie (si progression — résistance BRAF)"]$$,'S100-B + LDH = biomarqueurs de suivi. Immunothérapie (anti-PD1) : surveillance toxicité auto-immune'),
  (29,'Cancer Peau','Carcinome basocellulaire','initial',$$["📡 Dermoscopie +++", "🧪 Bilan standard préopératoire (NFS, coag)"]$$,NULL,'Diagnostic clinique + dermoscopique souvent suffisant. Biopsie si doute ou forme agressive'),
  (29,'Cancer Peau','Carcinome basocellulaire','confirmation',$$["🔬 Biopsie cutanée (punch ou shave)", "🔬 IHC : BerEP4 (+++), Bcl-2, CK5/6 (faible)", "🔬 Type histologique (nodulaire/superficiel/infiltrant/métatypique)"]$$,NULL,'Type infiltrant/métatypique = forme agressive → marges chirurgicales élargies ou chirurgie de Mohs'),
  (29,'Cancer Peau','Carcinome basocellulaire','extension',$$["📡 Scanner cervico-facial (si forme avancée locale)"]$$,$$["📡 Scanner TAP (si métastatique — exceptionnel)"]$$,'Extension rare — scanner uniquement si forme localement avancée non résécable ou récidivante'),
  (29,'Cancer Peau','Carcinome basocellulaire','suivi',$$["📡 Dermoscopie (annuelle — surveillance cutanée complète)", "📡 Examen clinique (tous les 6 mois × 5 ans)"]$$,NULL,'Risque de récidive locale et de nouvelles lésions élevé. Photoprotection +++ à vie'),
  (30,'Cancer Peau','Carcinome épidermoïde cutané','initial',$$["📡 Dermoscopie", "📡 Échographie ganglionnaire régionale (si ulcéré ou >2cm)", "🧪 Bilan standard préopératoire"]$$,NULL,'Ulcération + croissance rapide + terrain immunodéprimé = haut risque. Echo ganglionnaire systématique'),
  (30,'Cancer Peau','Carcinome épidermoïde cutané','confirmation',$$["🔬 Biopsie cutanée", "🔬 IHC : CK5/6 +++, p63, p40", "🔬 Degré de différenciation (bien/moyennement/peu différencié)", "🔬 Épaisseur tumorale (mm) — facteur pronostique"]$$,$$["🔬 HPV typage (si lésion génitale ou péri-unguéale)"]$$,'Peu différencié + épaisseur >6mm + péri-neural = haut risque de métastase ganglionnaire'),
  (30,'Cancer Peau','Carcinome épidermoïde cutané','extension',$$["📡 Échographie ganglionnaire +++", "📡 Scanner TAP (si ganglions palpables)"]$$,$$["📡 PET-Scan (si métastatique)", "🔬 Biopsie ganglionnaire sentinelle (si haut risque)"]$$,'Risque métastatique plus élevé que basocellulaire. Curage ganglionnaire si N+'),
  (30,'Cancer Peau','Carcinome épidermoïde cutané','suivi',$$["📡 Dermoscopie (tous les 6 mois)", "📡 Examen clinique + palpation ganglionnaire (tous les 3 mois × 2 ans)"]$$,$$["📡 Scanner TAP (si récidive ganglionnaire)"]$$,'Surveillance rapprochée 2 ans — 75% des récidives dans les 2 ans'),
  (31,'Cancer du Cerveau','Glioblastome (GBM)','initial',$$["📡 IRM cérébrale avec injection URGENTE +++", "🧪 NFS", "🧪 Bilan hépatique", "🧪 Cortisolémie (si corticoïdes)"]$$,NULL,'IRM = examen de référence. Prise de contraste en couronne + nécrose centrale = aspect typique GBM'),
  (31,'Cancer du Cerveau','Glioblastome (GBM)','confirmation',$$["🔬 Biopsie stéréotaxique ou exérèse chirurgicale", "🔬 IHC : GFAP (+++), IDH1 R132H (négatif GBM IDH-WT)", "🔬 PCR IDH1/IDH2 (muté = gliome grade 4 IDH-muté — meilleur pronostic)", "🔬 PCR TERT (muté = GBM IDH-WT souvent)", "🔬 FISH EGFR (amplifié dans 40%)", "🔬 Méthylation MGMT +++"]$$,$$["🔬 NGS panel gliome (CDKN2A, PTEN, TP53)", "🔬 FISH 1p/19q (oligodendrogliome si co-délétion)"]$$,'Méthylation MGMT = prédicteur de réponse au témozolomide. OBLIGATOIRE avant traitement'),
  (31,'Cancer du Cerveau','Glioblastome (GBM)','extension',$$["📡 IRM cérébrale complète (séquences standard + perfusion + spectroscopie)", "📡 IRM médullaire (si symptômes rachidiens)", "🧪 NFS + Bilan hépatique (avant témozolomide)"]$$,$$["📡 PET-Scan acides aminés (FET/MET) si disponible — délimitation tumorale"]$$,'IRM complète pré-opératoire pour planification neurochirurgicale (neuronavigation). Pas de scanner TAP body'),
  (31,'Cancer du Cerveau','Glioblastome (GBM)','suivi',$$["📡 IRM cérébrale (après chirurgie J2-J3, puis tous les 2-3 mois) +++", "🧪 NFS (toxicité témozolomide)", "🧪 Bilan hépatique"]$$,$$["📡 PET-Scan acides aminés (pseudo-progression vs progression vraie)"]$$,'Pseudo-progression fréquente à 3 mois (inflammation post-RT) — PET acides aminés aide à distinguer'),
  (32,'Cancer du Cerveau','Médulloblastome','initial',$$["📡 IRM cérébrale + médullaire URGENT +++", "🧪 NFS", "🧪 Bilan hépatique"]$$,NULL,'IRM médullaire OBLIGATOIRE dès le diagnostic — recherche de métastases leptoméningées'),
  (32,'Cancer du Cerveau','Médulloblastome','confirmation',$$["🔬 Biopsie/exérèse neurochirurgicale", "🔬 IHC : Synaptophysine, MAP2, sous-groupe moléculaire", "🔬 PCR/FISH : WNT (CTNNB1), SHH (PTCH1/SMO/SUFU), Groupe 3 (MYC), Groupe 4", "🔬 Cytologie LCR (ponction lombaire après décompression)"]$$,$$["🔬 NGS panel médulloblastome"]$$,'Sous-groupe WNT = excellent pronostic (>95%). Groupe 3 avec MYC amplifié = mauvais pronostic'),
  (32,'Cancer du Cerveau','Médulloblastome','extension',$$["📡 IRM cérébrale + médullaire complète", "📡 Scintigraphie osseuse (si symptômes)", "🔬 Cytologie LCR +++", "🔬 Myélogramme (si M3-M4)", "🧪 NFS + Bilan complet"]$$,NULL,'Stadification Chang obligatoire (M0-M4). M1 (LCR+) = traitement intensifié. M2-M4 = haut risque'),
  (32,'Cancer du Cerveau','Médulloblastome','suivi',$$["📡 IRM cérébrale + médullaire (tous les 3 mois × 2 ans puis semestriel)", "🔬 Cytologie LCR (annuelle)", "🧪 NFS (toxicité chimio)", "🧪 TSH (si irradiation)", "🧪 GH/IGF1 (déficit en GH post-RT fréquent chez enfant)"]$$,$$["📡 Bilan neuropsychologique (séquelles cognitives RT)"]$$,'Surveillance endocrinienne OBLIGATOIRE chez l''enfant irradié (GH, TSH, LH/FSH, cortisol)'),
  (33,'Cancer du Cerveau','Méningiome','initial',$$["📡 IRM cérébrale avec injection +++", "🧪 NFS", "🧪 Bilan standard"]$$,NULL,'IRM = diagnostic. Aspect typique (prise de contraste homogène + queue durale). Souvent asymptomatique'),
  (33,'Cancer du Cerveau','Méningiome','confirmation',$$["🔬 Biopsie ou exérèse neurochirurgicale", "🔬 IHC : EMA +++, Vimentine, PR (récepteurs progestérone)", "🔬 Grade OMS (I/II/III)", "🔬 PCR NF2 (monosomie 22q)", "🔬 PCR TRAF7/AKT1/SMO/KLF4 (grade I non-NF2)", "🔬 PCR CDKN2A/B (grade III)"]$$,$$["🔬 FISH CDKN2A homozygote (grade III — pronostic péjoratif)"]$$,'Grade I = bénin (surveillance ou chirurgie). Grade II-III = malin → traitement adjuvant'),
  (33,'Cancer du Cerveau','Méningiome','extension',$$["📡 IRM cérébrale complète (multi-séquences)", "📡 Angiographie cérébrale (si envahissement sinus)"]$$,$$["📡 Scanner TAP (si méningiome grade III — métastases exceptionnelles)"]$$,'Méningiome grade I : surveillance IRM seule si petit et asymptomatique. Pas de bilan systémique'),
  (33,'Cancer du Cerveau','Méningiome','suivi',$$["📡 IRM cérébrale (à 3 mois post-op, puis annuelle)"]$$,$$["📡 Angiographie (si récidive avec envahissement vasculaire)"]$$,'Grade I réséqué complet (Simpson I-II) = surveillance annuelle. Grade II-III = IRM trimestrielle × 2 ans'),
  (34,'Cancer Testicule','Séminome','initial',$$["📡 Échographie testiculaire URGENTE +++", "🧪 AFP (doit être normale dans séminome pur !!!)", "🧪 HCG totale (légèrement élevée possible)", "🧪 LDH", "🧪 NFS"]$$,NULL,'AFP NORMALE = séminome pur. Toute élévation AFP → non-séminome même si histo séminome'),
  (34,'Cancer Testicule','Séminome','confirmation',$$["🔬 Orchidectomie inguinale (pas scrotale) + examen anatomopathologique complet", "🔬 IHC : PLAP +++, OCT3/4, SALL4, AFP (négatif), HCG (négatif ou focale)", "🔬 Invasion vasculaire/lymphatique (facteur pronostique)"]$$,NULL,'Orchidectomie = traitement + diagnostic simultané. Voie inguinale OBLIGATOIRE (risque drainage scotal)'),
  (34,'Cancer Testicule','Séminome','extension',$$["📡 Scanner TAP (après orchidectomie)", "🧪 AFP post-orchidectomie +++", "🧪 HCG post-orchidectomie", "🧪 LDH post-orchidectomie", "🧪 Classification IGCCCG (pronostic)"]$$,$$["📡 IRM cérébrale + Scanner thoracique (si stade avancé)", "📡 PET-Scan FDG (résidu post-chimio séminome uniquement)"]$$,'Décroissance des marqueurs post-orchidectomie = OBLIGATOIRE à surveiller (demi-vie AFP: 7j, HCG: 3j)'),
  (34,'Cancer Testicule','Séminome','suivi',$$["🧪 AFP + HCG + LDH (tous les 3 mois × 2 ans)", "📡 Scanner TAP (tous les 6 mois × 3 ans)", "📡 Échographie testiculaire controlatérale (annuelle)"]$$,$$["📡 PET-Scan FDG (si résidu >3cm post-chimio séminome — décision traitement résidu)"]$$,'PET-Scan POST-chimio séminome : FDG+ = résidu viable → traitement. FDG- → surveillance même si masse résiduelle'),
  (35,'Cancer Testicule','Non-séminome (TGNS)','initial',$$["📡 Échographie testiculaire URGENTE", "🧪 AFP +++", "🧪 HCG totale +++", "🧪 LDH +++", "🧪 NFS + Bilan complet"]$$,NULL,'AFP très élevée = marqueur spécifique TGNS. HCG élévée = choriocarcinome. LDH = masse tumorale'),
  (35,'Cancer Testicule','Non-séminome (TGNS)','confirmation',$$["🔬 Orchidectomie inguinale + examen anatomopathologique", "🔬 IHC : AFP (+++), HCG, CD30 (choriocarcinome), PLAP, OCT3/4", "🔬 Composantes : tératome/choriocarcinome/tumeur sac vitellin/carcinome embryonnaire (%)", "🔬 Invasion vasculaire/lymphatique"]$$,NULL,'Le pourcentage de chaque composante influence le protocole chimio et le suivi des marqueurs'),
  (35,'Cancer Testicule','Non-séminome (TGNS)','extension',$$["📡 Scanner TAP", "📡 IRM cérébrale (si marqueurs très élevés ou symptômes — choriocarcinome)", "🧪 AFP post-orchidectomie (cinétique décroissance)", "🧪 HCG post-orchidectomie", "🧪 LDH", "🧪 Classification IGCCCG (pronostic)"]$$,$$["📡 Scanner thoracique haute résolution (métastases pulmonaires)"]$$,'Cinétique de décroissance des marqueurs = pronostic majeur. Demi-vie anormale → stade avancé'),
  (35,'Cancer Testicule','Non-séminome (TGNS)','suivi',$$["🧪 AFP + HCG + LDH (tous les mois × 1 an puis tous les 2 mois)", "📡 Scanner TAP (tous les 4-6 mois)", "📡 Échographie testiculaire controlatérale", "📡 IRM cérébrale (si HCG initiale très élevée)"]$$,$$["🔬 Exérèse résidu post-chimio (si résidu >1cm — tératome mature résiduel)"]$$,'Résidu post-BEP → exérèse chirurgicale OBLIGATOIRE (tératome non chimio-sensible). Marqueurs normalisés ?'),
  (36,'Neuroblastome','Neuroblastome','initial',$$["📡 Échographie abdominale URGENTE", "🧪 NSE +++", "🧪 LDH", "🧪 Ferritine", "🧪 Catécholamines urinaires (VMA + HVA) 24h +++", "🧪 NFS", "🧪 Bilan hépatique + rénal"]$$,NULL,'VMA+HVA urinaires = marqueurs quasi-pathognomoniques. Masse rétropéritonéale calcifiée chez enfant <5 ans'),
  (36,'Neuroblastome','Neuroblastome','confirmation',$$["🔬 Biopsie tumorale", "🔬 IHC : Synaptophysine, Chromogranine A, CD56, NSE, S100", "🔬 FISH N-MYC (amplification = mauvais pronostic) +++", "🔬 Caryotype (ALK mutation)", "🔬 Score histologique Shimada (favorable/défavorable)"]$$,$$["🔬 NGS panel neuroblastome (ALK/ATRX)"]$$,'NMYC amplifié = haut risque → traitement intensif + immunothérapie (dinutuximab). Score Shimada = pronostic'),
  (36,'Neuroblastome','Neuroblastome','extension',$$["📡 Scintigraphie MIBG (I-123) +++", "📡 Scanner TAP", "📡 IRM abdominale", "🔬 Myélogramme bilatéral (métastases fréquentes)", "🧪 NSE", "🧪 Ferritine", "🧪 LDH"]$$,$$["📡 PET-Scan FDG (si MIBG négatif — 10% des neuroblastomes)"]$$,'Scintigraphie MIBG = gold standard pour stadification et suivi. INRG staging (L1/L2/M/MS)'),
  (36,'Neuroblastome','Neuroblastome','suivi',$$["🧪 NSE (avant chaque cure)", "🧪 Catécholamines urinaires (VMA+HVA)", "🧪 Ferritine", "🧪 NFS + Bilan hépatique", "📡 Scintigraphie MIBG (évaluation réponse)", "📡 Scanner TAP"]$$,$$["🔬 Myélogramme (si MIBG+ initial)"]$$,'MIBG + NSE + VMA/HVA = trilogie de suivi. Rémission complète = MIBG négatif + marqueurs normaux'),
  (37,'Tumeur de Wilms','Néphroblastome','initial',$$["📡 Échographie rénale +++", "📡 Scanner TAP", "🧪 NFS", "🧪 Bilan rénal (créatinine + DFG)", "🧪 LDH", "🧪 Bilan hépatique"]$$,NULL,'Masse rénale chez enfant 1-5 ans = Wilms jusqu''à preuve contraire. Échographie en urgence'),
  (37,'Tumeur de Wilms','Néphroblastome','confirmation',$$["🔬 Biopsie (ou exérèse directe si résécable — protocole SIOP)", "🔬 IHC : WT1, PAX2, CD57", "🔬 PCR WT1 (mutation) + 1p/16q (perte hétérozygotie)", "🔬 Blastes diffus (facteur de risque élevé)"]$$,$$["🔬 Génétique constitutionnelle WT1 (si anomalies génitales associées — Denys-Drash)"]$$,'Protocole SIOP (Europe) : chimio néoadjuvante AVANT chirurgie → réduit tumeur + risque rupture'),
  (37,'Tumeur de Wilms','Néphroblastome','extension',$$["📡 Scanner TAP (envahissement VCI + poumons)", "📡 IRM rénale bilatérale (Wilms bilatéral — 5-7%)", "🧪 NFS + Bilan rénal", "🧪 LDH"]$$,$$["📡 IRM cardiaque (si thrombus VCI jusqu'aux cavités droites)"]$$,'Thrombus de la veine cave inférieure fréquent → scanner avec fenêtre vasculaire. Bilatéral = chirurgie conservatrice'),
  (37,'Tumeur de Wilms','Néphroblastome','suivi',$$["📡 Échographie rénale (tous les 3 mois × 2 ans)", "📡 Radiographie thorax (tous les 3 mois — métas pulmonaires)", "🧪 NFS + Bilan rénal", "🧪 LDH"]$$,$$["📡 Scanner TAP (si récidive suspectée)"]$$,'Surveillance rein controlatéral +++ (risque Wilms bilatéral 5-7%). Fonction rénale à préserver'),
  (38,'Rétinoblastome','Rétinoblastome','initial',$$["📡 Examen fond d'œil sous AG +++", "📡 Écho-oculaire (B-scan)", "📡 IRM oculaire + orbite", "🧪 NFS", "🧪 Bilan standard"]$$,NULL,'Leucocorie (reflet blanc pupillaire) chez enfant <5 ans = urgence ophtalmologique absolue'),
  (38,'Rétinoblastome','Rétinoblastome','confirmation',$$["🔬 Pas de biopsie (risque d'essaimage) — diagnostic clinique + imagerie", "🔬 PCR/NGS mutation RB1 constitutionnelle (sang + tumeur si énucléée)", "🔬 IHC sur pièce d'énucléation : RB1 (négatif), Ki67, p53", "🔬 Caryotype constitutionnel (si bilatéral)"]$$,NULL,'JAMAIS de biopsie transpupillaire — essaimage systématique. Diagnostic clinique + IRM + RB1 génétique'),
  (38,'Rétinoblastome','Rétinoblastome','extension',$$["📡 IRM oculaire bilatérale + base du crâne +++", "📡 IRM médullaire (si envahissement nerf optique)", "📡 Scanner crânien", "🔬 Cytologie LCR (si extension SNC)", "🔬 Myélogramme (si extension systémique)", "🧪 NFS + Bilan complet"]$$,NULL,'Groupe International E (envahissement choroïde massive + nerf optique) = traitement systémique + greffe'),
  (38,'Rétinoblastome','Rétinoblastome','suivi',$$["📡 Fond d'œil sous AG (tous les 3 mois × 3 ans puis annuel)", "📡 IRM oculaire (annuelle)", "🔬 Suivi génétique RB1 (fratrie + parents si héréditaire)"]$$,$$["📡 Imagerie corps entier annuelle (si RB1 constitutionnel — risque 2e cancer : ostéosarcome ++)"]$$,'RB1 constitutionnel = risque majeur de 2e cancer (ostéosarcome, mélanome) → surveillance corps entier à vie'),
  (39,'Sarcome Osseux','Ostéosarcome','initial',$$["📡 Radiographies osseuses F+P du membre +++", "📡 IRM du membre (extension locale) +++", "🧪 PAL (phosphatase alcaline) +++", "🧪 LDH", "🧪 NFS", "🧪 Bilan hépatique + rénal"]$$,NULL,'Radiographies + IRM en URGENCE. Ne pas biopsier avant imagerie complète — risque de contamination'),
  (39,'Sarcome Osseux','Ostéosarcome','confirmation',$$["🔬 Biopsie osseuse (voie planifiée avec chirurgien — même voie que résection future)", "🔬 IHC : Vimentine, Ostéocalcine, CD99, S100", "🔬 PCR RUNX2", "🔬 Caryotype (complexe)", "🔬 PAL sérique (corrèle avec masse tumorale)"]$$,$$["🔬 NGS panel sarcome (TP53/RB1/CDKN2A — pronostic)"]$$,'VOIE DE BIOPSIE CRUCIALE — doit être planifiée conjointement avec le chirurgien orthopédiste oncologue'),
  (39,'Sarcome Osseux','Ostéosarcome','extension',$$["📡 Scanner thoracique haute résolution +++", "📡 Scintigraphie osseuse corps entier", "📡 IRM corps entier (métas osseuses)", "🧪 PAL", "🧪 LDH", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan FDG (évaluation réponse néoadjuvante)"]$$,'Poumons = site métastatique #1 (scanner thoracique haute résolution obligatoire). Os = site #2'),
  (39,'Sarcome Osseux','Ostéosarcome','suivi',$$["📡 IRM du membre (tous les 3 mois × 2 ans)", "📡 Scanner thoracique (tous les 3 mois × 2 ans)", "📡 Scintigraphie osseuse (tous les 6 mois)", "🧪 PAL + LDH", "🧪 NFS + Bilan hépatique"]$$,$$["📡 PET-Scan (si récidive suspectée)"]$$,'Surveillance pulmonaire rapprochée — 80% des récidives métastatiques sont pulmonaires'),
  (40,'Sarcome Osseux','Sarcome d''Ewing','initial',$$["📡 Radiographies osseuses (aspect feuilleté 'bulbe d'oignon')", "📡 IRM du membre/axe +++", "🧪 LDH +++", "🧪 NFS", "🧪 VS", "🧪 Bilan hépatique + rénal"]$$,NULL,'Aspect radiologique ''bulbe d''oignon'' + LDH élevé chez adolescent = Ewing jusqu''à preuve contraire'),
  (40,'Sarcome Osseux','Sarcome d''Ewing','confirmation',$$["🔬 Biopsie osseuse (voie planifiée)", "🔬 IHC : CD99 (membranaire +++) , FLI1, NKX2.2", "🔬 FISH t(11;22)(q24;q12) EWS-FLI1 +++", "🔬 PCR EWS-FLI1 (type 1/2) — facteur pronostique", "🔬 PCR EWS-ERG (t7;22 — 5-10%)"]$$,$$["🔬 NGS panel sarcome"]$$,'PCR/FISH EWS-FLI1 OBLIGATOIRE — confirme le diagnostic. Type 1 (fusion exon 7-6) = meilleur pronostic'),
  (40,'Sarcome Osseux','Sarcome d''Ewing','extension',$$["📡 Scanner thoracique haute résolution", "📡 Scintigraphie osseuse", "📡 IRM corps entier", "🔬 Myélogramme bilatéral (métas médullaires)", "🧪 LDH", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan FDG (évaluation réponse induction)"]$$,'Myélogramme OBLIGATOIRE — Ewing métastase dans la moelle dans 20% des cas (stade M)'),
  (40,'Sarcome Osseux','Sarcome d''Ewing','suivi',$$["📡 IRM du membre (tous les 3 mois)", "📡 Scanner thoracique (tous les 3 mois)", "📡 Scintigraphie osseuse (tous les 6 mois)", "🧪 LDH", "🧪 NFS + Bilan hépatique"]$$,$$["📡 PET-Scan (si récidive)", "🔬 Myélogramme (si cytopénies)"]$$,'Récidive dans les 2 ans = très mauvais pronostic. Greffe allogénique si récidive précoce'),
  (41,'Sarcome Tissus Mous','Sarcome des tissus mous','initial',$$["📡 IRM du membre/région +++", "📡 Échographie (si superficiel)", "🧪 LDH", "🧪 NFS", "🧪 Bilan hépatique + rénal"]$$,NULL,'IRM = gold standard pour caractérisation. Toute masse des tissus mous >5cm ou profonde = biopsie urgente'),
  (41,'Sarcome Tissus Mous','Sarcome des tissus mous','confirmation',$$["🔬 Biopsie (voie soigneusement planifiée en centre expert)", "🔬 IHC large panel (selon sous-type suspecté)", "🔬 FISH/PCR translocation spécifique (SYT-SSX synovial, FUS-CHOP liposarcome, EWS-ATF1 à cellules claires)", "🔬 Grade FNCLCC (1-3) +++", "🔬 NGS panel sarcome étendu"]$$,NULL,'CENTRE EXPERT OBLIGATOIRE — >50 sous-types histologiques. Grade FNCLCC = principal facteur pronostique'),
  (41,'Sarcome Tissus Mous','Sarcome des tissus mous','extension',$$["📡 Scanner thoracique haute résolution +++", "📡 IRM région (extension locale)", "🧪 LDH", "🧪 NFS + Bilan complet"]$$,$$["📡 PET-Scan FDG (si grade élevé ou synovial)", "📡 Scanner TAP (si rétropéritonéal)", "📡 Scintigraphie osseuse (si sarcome osseux invasif)"]$$,'Poumon = site métastatique #1. Abdomen si liposarcome rétropéritonéal — scanner abdominal obligatoire'),
  (41,'Sarcome Tissus Mous','Sarcome des tissus mous','suivi',$$["📡 IRM locale (tous les 3-4 mois × 2 ans)", "📡 Scanner thoracique (tous les 3-4 mois × 3 ans)", "🧪 LDH", "🧪 NFS + Bilan hépatique"]$$,$$["📡 PET-Scan (si récidive)"]$$,'Surveillance locale + pulmonaire rapprochée. 80% des récidives dans les 3 ans'),
  (42,'Cancer Œsophage','Carcinome épidermoïde œsophagien','initial',$$["📡 FOGD (fibroscopie) avec biopsies +++", "🧪 NFS (anémie)", "🧪 Albuminémie (dénutrition)", "🧪 SCC (J0)", "🧪 Bilan hépatique"]$$,NULL,'Dysphagie progressive = FOGD urgente. Biopsies multiples de toute lésion suspecte'),
  (42,'Cancer Œsophage','Carcinome épidermoïde œsophagien','confirmation',$$["🔬 Biopsies endoscopiques multiples", "🔬 IHC : CK5/6, p40, p63 (+++), CK7 (négatif)", "🔬 IHC : PDL1 (CPS)", "🔬 HPV typage (œsophage distal)"]$$,$$["🔬 NGS panel (FGFR/EGFR)"]$$,'PDL1 CPS ≥10 → pembrolizumab en 1ère ligne. HPV positif = meilleure réponse chimio-RT'),
  (42,'Cancer Œsophage','Carcinome épidermoïde œsophagien','extension',$$["📡 Écho-endoscopie (stade T et N local) +++", "📡 Scanner TAP (métas)", "📡 PET-Scan FDG", "🧪 SCC", "🧪 Albuminémie", "🧪 NFS + Bilan complet"]$$,$$["📡 Bronchoscopie (si envahissement trachéo-bronchique)", "📡 Laparoscopie (si jonction œso-gastrique)"]$$,'Écho-endoscopie OBLIGATOIRE pour stade T — décide chirurgie vs radio-chimio. PET-Scan = N à distance'),
  (42,'Cancer Œsophage','Carcinome épidermoïde œsophagien','suivi',$$["📡 FOGD (tous les 6 mois × 2 ans)", "📡 Scanner TAP (tous les 6 mois)", "🧪 SCC", "🧪 Albuminémie", "🧪 NFS + Bilan hépatique"]$$,$$["📡 PET-Scan (si SCC montant)"]$$,'Surveillance nutritionnelle OBLIGATOIRE — dénutrition = principal facteur de morbi-mortalité'),
  (43,'Cancer Œsophage','Adénocarcinome œsophagien','initial',$$["📡 FOGD avec biopsies et chromoendoscopie +++", "🧪 NFS", "🧪 Albuminémie", "🧪 CEA (J0)", "🧪 CA 19-9 (J0)"]$$,NULL,'Souvent sur endobrachyœsophage (Barrett). Chromoendoscopie + biopsies étagées au cardia'),
  (43,'Cancer Œsophage','Adénocarcinome œsophagien','confirmation',$$["🔬 Biopsies endoscopiques", "🔬 IHC : HER2 (score 0-3+) +++", "🔬 FISH HER2 si score 2+", "🔬 IHC : MMR + PCR MSI", "🔬 IHC : PDL1 (CPS)", "🔬 PCR CLDN18.2"]$$,$$["🔬 NGS panel"]$$,'HER2 positif → trastuzumab en 1ère ligne. MSI → pembrolizumab. PDL1 CPS ≥5 → pembrolizumab+chimio'),
  (43,'Cancer Œsophage','Adénocarcinome œsophagien','extension',$$["📡 Écho-endoscopie +++", "📡 Scanner TAP", "📡 PET-Scan FDG", "🧪 CEA", "🧪 CA 19-9", "🧪 Albuminémie", "🧪 NFS + Bilan complet"]$$,$$["📡 Laparoscopie de staging (carcinose)"]$$,'Similaire au cancer gastrique. Même algorithme de biomarqueurs et de stadification'),
  (43,'Cancer Œsophage','Adénocarcinome œsophagien','suivi',$$["📡 FOGD (annuelle — surveillance Barrett résiduel)", "📡 Scanner TAP (tous les 6 mois)", "🧪 CEA", "🧪 CA 19-9", "🧪 Albuminémie"]$$,$$["📡 PET-Scan (si récidive)"]$$,'Surveillance Barrett résiduel par FOGD — risque de 2e cancer. Supplémentation nutritionnelle +'),
  (44,'Cancer du Larynx','Carcinome épidermoïde laryngé','initial',$$["📡 Laryngoscopie indirecte / Nasofibroscopie", "🧪 NFS", "🧪 SCC (J0)", "🧪 Bilan hépatique", "🧪 Albuminémie"]$$,NULL,'Dysphonie persistante >3 semaines chez fumeur → nasofibroscopie URGENTE'),
  (44,'Cancer du Larynx','Carcinome épidermoïde laryngé','confirmation',$$["🔬 Biopsie laryngoscopique (panendoscopie sous AG)", "🔬 IHC : CK5/6, p63, p40", "🔬 HPV typage (p16 IHC)", "📡 Panendoscopie (recherche 2e cancer synchrone voies aéro-digestives)"]$$,NULL,'Panendoscopie OBLIGATOIRE — 2e cancer synchrone dans 3-5% des cancers ORL (tabac/alcool)'),
  (44,'Cancer du Larynx','Carcinome épidermoïde laryngé','extension',$$["📡 IRM cervico-faciale +++", "📡 Scanner cervico-thoracique", "📡 PET-Scan FDG", "🧪 SCC", "🧪 Albuminémie", "🧪 NFS + Bilan complet"]$$,NULL,'IRM = meilleure évaluation extension locale (cartilages laryngés). Scanner = ADP cervicales + métas'),
  (44,'Cancer du Larynx','Carcinome épidermoïde laryngé','suivi',$$["📡 Nasofibroscopie (tous les 3 mois × 2 ans)", "📡 Scanner cervico-thoracique (tous les 6 mois)", "🧪 SCC", "🧪 TSH (si irradiation cervicale)", "🧪 Albuminémie"]$$,$$["📡 PET-Scan (si SCC montant)", "📡 IRM (si récidive locale)"]$$,'TSH à surveiller si irradiation cervicale — hypothyroïdie dans 20-30% des cas à 2 ans'),
  (45,'Cancer de la Langue','Carcinome épidermoïde lingual','initial',$$["📡 Nasofibroscopie + examen endobuccal", "🧪 NFS", "🧪 SCC (J0)", "🧪 Albuminémie", "🧪 Bilan hépatique"]$$,NULL,'Ulcération linguale indolore persistante >3 semaines = biopsie urgente'),
  (45,'Cancer de la Langue','Carcinome épidermoïde lingual','confirmation',$$["🔬 Biopsie linguale sous AL ou AG", "🔬 IHC : CK5/6, p63", "🔬 p16 IHC + HPV PCR (HPV 16) +++", "📡 Panendoscopie (2e cancer synchrone)"]$$,NULL,'p16 positif (HPV+) = meilleur pronostic, traitement déescaladé possible. En augmentation chez <50 ans'),
  (45,'Cancer de la Langue','Carcinome épidermoïde lingual','extension',$$["📡 IRM cervico-faciale +++", "📡 Panoramique dentaire (envahissement mandibule)", "📡 Scanner cervico-thoracique", "📡 PET-Scan FDG", "🧪 SCC", "🧪 Albuminémie"]$$,NULL,'IRM évalue l''invasion musculaire profonde et l''os mandibulaire. Panoramique = lyse osseuse mandibulaire'),
  (45,'Cancer de la Langue','Carcinome épidermoïde lingual','suivi',$$["📡 IRM cervico-faciale (tous les 3-6 mois)", "📡 Nasofibroscopie (tous les 3 mois)", "📡 Scanner thoracique (annuel)", "🧪 SCC", "🧪 TSH (si irradiation)"]$$,$$["📡 PET-Scan (si récidive)"]$$,'Suivi orthophonique et nutritionnel OBLIGATOIRE — séquelles fonctionnelles (déglutition, phonation)'),
  (46,'Cancer Nasopharynx','Carcinome du nasopharynx (NPC)','initial',$$["📡 Nasofibroscopie +++", "🧪 PCR EBV quantitative (ADN viral) +++", "🧪 Sérologies EBV (VCA IgA) +++", "🧪 NFS", "🧪 Bilan hépatique"]$$,NULL,'EBV ADN plasmatique + VCA IgA = marqueurs quasi-diagnostiques dans contexte maghrébin'),
  (46,'Cancer Nasopharynx','Carcinome du nasopharynx (NPC)','confirmation',$$["🔬 Biopsie nasopharyngée (nasofibroscopie)", "🔬 IHC : CK (AE1/AE3), EBER (in situ hybridization EBV) +++", "🔬 Type OMS (I/II/III — type III non-kératinisant = plus fréquent Algérie)"]$$,NULL,'EBER positif = quasi-pathognomonique du NPC. Type III (indifférencié) = meilleure réponse à chimio-RT'),
  (46,'Cancer Nasopharynx','Carcinome du nasopharynx (NPC)','extension',$$["📡 IRM nasopharynx + base du crâne + cou +++", "📡 Scanner cervico-TAP", "📡 PET-Scan FDG", "🧪 PCR EBV quantitative (J0 — baseline)", "🧪 VCA IgA", "🧪 NFS + Bilan complet"]$$,NULL,'IRM base du crâne OBLIGATOIRE — extension intracrânienne fréquente (foramen ovale/lacéré). PET = N à distance'),
  (46,'Cancer Nasopharynx','Carcinome du nasopharynx (NPC)','suivi',$$["🧪 PCR EBV quantitative (tous les 3 mois) +++", "🧪 VCA IgA", "📡 IRM nasopharynx (à 3 mois puis semestrielle)", "📡 Scanner TAP (annuel)", "🧪 TSH (irradiation cervicale)"]$$,$$["📡 PET-Scan (si EBV montant sans lésion visible)"]$$,'PCR EBV = biomarqueur de suivi gold standard pour NPC. Remontée ADN viral = récidive précoce détectable'),
  (47,'Cancer Glande Salivaire','Carcinome adénoïde kystique','initial',$$["📡 Échographie glande salivaire (parotide/sous-max)", "📡 IRM cervico-faciale +++", "🧪 NFS", "🧪 Bilan standard"]$$,NULL,'Masse salivaire indolore à croissance lente + paralysie faciale = carcinome jusqu''à preuve contraire'),
  (47,'Cancer Glande Salivaire','Carcinome adénoïde kystique','confirmation',$$["🔬 Biopsie (FNA ou biopsie chirurgicale ouverte)", "🔬 IHC : CK7, S100, SMA, CD117 (c-KIT) +++", "🔬 FISH MYB-NFIB (t(6;9)) +++", "🔬 Pattern histologique (tubulaire/cribriforme/solide — pronostic)"]$$,NULL,'Pattern solide = mauvais pronostic. FISH MYB-NFIB confirme dans 60%. Infiltration péri-neurale typique'),
  (47,'Cancer Glande Salivaire','Carcinome adénoïde kystique','extension',$$["📡 IRM cervico-faciale étendue (troncs nerveux)", "📡 Scanner cervico-TAP", "📡 Scanner thoracique haute résolution (métas pulmonaires tardives)", "🧪 NFS + Bilan standard"]$$,$$["📡 PET-Scan FDG"]$$,'Extension péri-neurale à suivre sur IRM (nerf facial/trijumeau). Métas pulmonaires tardives (5-15 ans)'),
  (47,'Cancer Glande Salivaire','Carcinome adénoïde kystique','suivi',$$["📡 IRM cervico-faciale (annuelle × 10 ans)", "📡 Scanner thoracique (annuel × 10 ans) +++", "📡 Nasofibroscopie (annuelle)", "🧪 NFS + Bilan standard"]$$,NULL,'Surveillance à 10 ans OBLIGATOIRE — récidives très tardives caractéristiques. Métas pulmonaires à 10-15 ans'),
  (48,'Cancer Vésicule Biliaire','Adénocarcinome vésiculaire','initial',$$["📡 Échographie abdominale +++", "🧪 CA 19-9", "🧪 CEA", "🧪 Bilan hépatique (bilirubine)", "🧪 NFS"]$$,NULL,'Souvent découverte fortuite sur pièce de cholécystectomie. Ou masse vésicale sur écho'),
  (48,'Cancer Vésicule Biliaire','Adénocarcinome vésiculaire','confirmation',$$["🔬 Biopsie écho-guidée ou peropératoire", "🔬 IHC : CK7, CK20, MUC1, MUC5AC, CDX2", "🔬 PCR HER2, IDH1, FGFR2 (cholangiocarcinome associé)", "🔬 IHC MMR + PCR MSI"]$$,NULL,'Souvent diagnostiqué sur pièce de cholécystectomie — examen anatomopathologique systématique obligatoire'),
  (48,'Cancer Vésicule Biliaire','Adénocarcinome vésiculaire','extension',$$["📡 IRM biliaire (CPRM) +++", "📡 Scanner TAP", "📡 PET-Scan FDG", "🧪 CA 19-9", "🧪 CEA", "🧪 Bilan hépatique complet"]$$,$$["📡 Artériographie hépatique (si résection hépatique planifiée)"]$$,'CPRM = évalue les voies biliaires. Envahissement hépatique + ADP = stade avancé non résécable'),
  (48,'Cancer Vésicule Biliaire','Adénocarcinome vésiculaire','suivi',$$["📡 Scanner TAP (tous les 3-6 mois)", "🧪 CA 19-9", "🧪 CEA", "🧪 Bilan hépatique"]$$,$$["📡 IRM hépatique (si métas hépatiques)"]$$,'Pronostic sombre. CA 19-9 = marqueur de suivi. Survie médiane 6-12 mois stade IV'),
  (49,'Mésothéliome','Mésothéliome pleural malin','initial',$$["📡 Radiographie thorax (épanchement pleural unilatéral)", "📡 Scanner thoracique", "🧪 Mésothéline sérique +++", "🧪 Mégaline sérique", "🧪 NFS", "🧪 Bilan hépatique"]$$,NULL,'Épanchement pleural récidivant unilatéral + antécédent amiante = mésothéliome jusqu''à preuve contraire'),
  (49,'Mésothéliome','Mésothéliome pleural malin','confirmation',$$["🔬 Thoracoscopie + biopsies pleurales multiples +++", "🔬 IHC : Calrétinine +++, WT-1, D2-40, CK5/6 (positifs mésothéliome)", "🔬 IHC : CEA, TTF-1, MOC31, BerEP4 (négatifs — éliminent adénocarcinome)", "🔬 BAP1 (perte = confirme malignité) +++", "🔬 FISH homozygote 9p21 (CDKN2A)"]$$,$$["🔬 Cytologie du liquide pleural (insuffisante seule)"]$$,'BAP1 perdu + FISH CDKN2A délété = diagnostic de certitude malignité. Thoracoscopie >> simple ponction'),
  (49,'Mésothéliome','Mésothéliome pleural malin','extension',$$["📡 Scanner TAP +++", "📡 IRM thoracique (extension diaphragme/péricarde)", "📡 PET-Scan FDG", "🧪 Mésothéline", "🧪 NFS + Bilan complet"]$$,NULL,'IRM évalue l''envahissement du diaphragme et du péricarde — détermine la résécabilité'),
  (49,'Mésothéliome','Mésothéliome pleural malin','suivi',$$["📡 Scanner thoracique (tous les 3 mois)", "🧪 Mésothéline", "🧪 NFS + Bilan hépatique", "🧪 Créatinine (pemetrexed + cisplatine)"]$$,$$["📡 PET-Scan (si progression)"]$$,'Mésothéline = marqueur de suivi de réponse. Corrélation avec réponse au traitement'),
  (50,'Cancer Surrénales','Carcinome corticosurrénalien','initial',$$["📡 Scanner surrénalien +++", "🧪 Cortisol (libre urinaire 24h + test de freinage)", "🧪 SDHA/SDHB", "🧪 Catécholamines urinaires (éliminer phéochromocytome)", "🧪 Aldostérone/Rénine", "🧪 Androgènes (DHEA-S, testostérone)", "🧪 NFS"]$$,NULL,'Bilan hormonal OBLIGATOIRE avant toute biopsie — phéochromocytome non reconnu = risque vital (poussée hypertensive)'),
  (50,'Cancer Surrénales','Carcinome corticosurrénalien','confirmation',$$["📡 IRM surrénale (caractérisation — lipides, wash-out)", "🔬 Biopsie surrénale (SEULEMENT si phéochromocytome exclu)", "🔬 IHC : SF-1 (+++), Inhibine, Melan-A, Ki67", "🔬 Score de Weiss histologique (≥3/9 = malin)", "🔬 PCR TP53 + CTNNB1 (bêta-caténine)"]$$,$$["🔬 Test génétique constitutionnel (Li-Fraumeni, MEN1, Lynch)"]$$,'SF-1 positif = cellule corticosurrénalienne. Score de Weiss ≥3 = carcinome. TP53 Li-Fraumeni chez enfant'),
  (50,'Cancer Surrénales','Carcinome corticosurrénalien','extension',$$["📡 Scanner TAP", "📡 PET-Scan FDG ou scintigraphie +++", "🧪 Cortisol libre urinaire (hypercorticisme)", "🧪 NFS + Bilan complet"]$$,$$["📡 Scintigraphie NP-59 (si fonctionnel)"]$$,'Cortisol très élevé = syndrome de Cushing paranéoplasique. Risque infectieux ++ (immunodépression)'),
  (50,'Cancer Surrénales','Carcinome corticosurrénalien','suivi',$$["📡 Scanner TAP (tous les 3 mois)", "🧪 Cortisol libre urinaire", "🧪 DHEA-S + Androgènes", "🧪 NFS + Bilan hépatique (mitotane — toxicité hépatique)", "🧪 Mitotanémie (taux thérapeutique 14-20 mg/L)"]$$,$$["📡 PET-Scan (si récidive)"]$$,'Mitotane = traitement adjuvant. Taux sérique à surveiller mensuellement. Insuffisance surrénalienne post-op'),
  (51,'Cancer Anal','Carcinome épidermoïde anal','initial',$$["📡 Anuscopie / Rectoscopie", "📡 Écho-endoscopie anale", "🧪 NFS", "🧪 SCC (J0)", "🧪 Sérologie VIH (prévalence élevée)"]$$,NULL,'Saignement anal + masse indurée = biopsie urgente. Sérologie VIH systématique — prévalence 30-40% chez H/H'),
  (51,'Cancer Anal','Carcinome épidermoïde anal','confirmation',$$["🔬 Biopsie anale", "🔬 IHC : CK5/6, p63", "🔬 HPV génotypage (16/18) +++", "🔬 p16 IHC (surrogate HPV)"]$$,NULL,'HPV 16 = 80% des cancers anaux. p16 positif = bon pronostic, meilleure réponse chimio-RT'),
  (51,'Cancer Anal','Carcinome épidermoïde anal','extension',$$["📡 IRM pelvienne +++", "📡 Scanner TAP", "📡 PET-Scan FDG (ganglions inguinaux occultes)", "🧪 SCC", "🧪 NFS + Bilan complet"]$$,NULL,'Radio-chimio (Nigro) = traitement standard — PAS de chirurgie en 1ère intention. PET = N inguinaux'),
  (51,'Cancer Anal','Carcinome épidermoïde anal','suivi',$$["📡 IRM pelvienne (à 3 mois post-traitement — évaluation réponse)", "📡 Anuscopie (tous les 6 mois)", "🧪 SCC", "📡 PET-Scan (si réponse incomplète à 6 mois)"]$$,NULL,'Réponse complète peut prendre 6 mois — ne pas opérer trop tôt. PET à 6 mois si résidu sur IRM'),
  (52,'Cancer du Pénis','Carcinome épidermoïde pénien','initial',$$["📡 Écho-pénienne", "📡 Écho ganglionnaire inguinale", "🧪 NFS", "🧪 SCC (J0)", "🧪 Bilan standard"]$$,NULL,'Lésion suspecte glande/prépuce + ADP inguinales = bilan urgent'),
  (52,'Cancer du Pénis','Carcinome épidermoïde pénien','confirmation',$$["🔬 Biopsie pénienne", "🔬 IHC : CK5/6, p63", "🔬 HPV génotypage", "🔬 p16 IHC", "🔬 Profondeur d'invasion (facteur pronostique)"]$$,NULL,'Profondeur invasion >5mm = risque métastatique élevé → ganglion sentinelle ou curage inguinal'),
  (52,'Cancer du Pénis','Carcinome épidermoïde pénien','extension',$$["📡 IRM pelvienne + pénis", "📡 Scanner TAP", "📡 PET-Scan FDG", "🧪 SCC", "🧪 NFS + Bilan complet"]$$,NULL,'IRM évalue profondeur invasion et corps caverneux. Curage inguinal si N+'),
  (52,'Cancer du Pénis','Carcinome épidermoïde pénien','suivi',$$["📡 Examen clinique + palpation inguinale (tous les 3 mois)", "📡 Écho inguinale", "🧪 SCC"]$$,$$["📡 Scanner TAP (si SCC montant)"]$$,'Surveillance inguinale rapprochée — ADP inguinales tardives possibles 1-2 ans après traitement'),
  (53,'Cancer Vaginal','Carcinome épidermoïde vaginal','initial',$$["📡 Examen gynécologique + colposcopie vaginale", "🧪 NFS", "🧪 SCC (J0)", "🧪 Frottis vaginal"]$$,NULL,'Souvent secondaire à cancer du col — anamnèse + HPV typage'),
  (53,'Cancer Vaginal','Carcinome épidermoïde vaginal','confirmation',$$["🔬 Biopsie vaginale", "🔬 IHC : CK5/6, p63", "🔬 HPV génotypage + p16"]$$,NULL,'Éliminer cancer du col et de la vulve avant de retenir l''origine vaginale primitive'),
  (53,'Cancer Vaginal','Carcinome épidermoïde vaginal','extension',$$["📡 IRM pelvienne +++", "📡 Scanner TAP", "📡 PET-Scan FDG", "🧪 SCC", "🧪 NFS + Bilan complet"]$$,NULL,'IRM pelvienne = évaluation extension locale. Même logique que cancer du col'),
  (53,'Cancer Vaginal','Carcinome épidermoïde vaginal','suivi',$$["📡 IRM pelvienne (à 3 mois puis semestrielle)", "📡 Colposcopie (annuelle)", "🧪 SCC"]$$,$$["📡 PET-Scan (si récidive)"]$$,'Surveillance gynécologique + IRM. Résultats traitement similaires au col de l''utérus'),
  (54,'Cancer Vulvaire','Carcinome épidermoïde vulvaire','initial',$$["📡 Examen clinique vulvaire", "📡 Écho inguinale", "🧪 NFS", "🧪 SCC (J0)"]$$,NULL,'Prurit vulvaire chronique + ulcération + lichen scléreux = surveillance rapprochée + biopsie si suspect'),
  (54,'Cancer Vulvaire','Carcinome épidermoïde vulvaire','confirmation',$$["🔬 Biopsie vulvaire (punch biopsy)", "🔬 IHC : CK5/6, p63", "🔬 HPV typage + p16 (voie HPV ou lichen scléreux)", "🔬 Profondeur invasion (mm)"]$$,NULL,'2 voies : HPV (femme jeune, p16+) vs Lichen scléreux (femme âgée, p16-). Pronostic similaire'),
  (54,'Cancer Vulvaire','Carcinome épidermoïde vulvaire','extension',$$["📡 IRM pelvienne +++", "📡 Scanner TAP", "📡 PET-Scan FDG (N inguinaux)", "🧪 SCC", "🧪 NFS + Bilan complet"]$$,NULL,'Ganglion sentinelle si T1b-T2 N0 clinique — évite curage inguinal systématique et ses séquelles'),
  (54,'Cancer Vulvaire','Carcinome épidermoïde vulvaire','suivi',$$["📡 Examen clinique (tous les 3 mois × 2 ans)", "📡 Écho inguinale", "🧪 SCC"]$$,$$["📡 IRM (si récidive locale)", "📡 Scanner TAP (si ADP inguinales)"]$$,'Surveillance inguinale = priorité. 30% de récidives locales à 5 ans'),
  (55,'Tumeur Pinéale','Germinome / Pinéalome','initial',$$["📡 IRM cérébrale +++", "🧪 AFP (plasmatique)", "🧪 HCG totale", "🧪 NFS", "🧪 Bilan standard"]$$,NULL,'Syndrome de Parinaud (paralysie regard vers le haut) + hydrocéphalie + ↑ AFP/HCG = germinome'),
  (55,'Tumeur Pinéale','Germinome / Pinéalome','confirmation',$$["🔬 Biopsie stéréotaxique", "🔬 IHC : OCT3/4, PLAP, CD117 (c-KIT) — germinome", "🔬 AFP (négatif germinome pur)", "🔬 HCG (β : <100 germinome pur, très élevé choriocarcinome)", "🔬 Cytologie LCR"]$$,NULL,'AFP + HCG différencient le sous-type. Germinome pur (AFP-/HCG bas) = excellent pronostic'),
  (55,'Tumeur Pinéale','Germinome / Pinéalome','extension',$$["📡 IRM cérébrale + médullaire entière +++", "🔬 Cytologie LCR (ponction lombaire)", "🧪 AFP + HCG (LCR + plasma)", "🧪 NFS + Bilan complet"]$$,NULL,'Dissémination leptoméningée = IRM médullaire + LCR OBLIGATOIRES. M+ = traitement intensifié'),
  (55,'Tumeur Pinéale','Germinome / Pinéalome','suivi',$$["📡 IRM cérébrale + médullaire (tous les 3 mois × 2 ans)", "🧪 AFP + HCG (plasma + LCR si + initialement)", "🧪 TSH + GH/IGF1 (irradiation — insuffisances hypophysaires)", "🧪 Cortisol + LH/FSH"]$$,NULL,'Surveillance endocrinienne OBLIGATOIRE post-irradiation — hypopituitarisme fréquent (diabète insipide surtout)'),
  (56,'Tumeur Carcinoïde','Tumeur neuroendocrine (TNE)','initial',$$["📡 Échographie abdominale", "🧪 Chromogranine A (CgA) +++", "🧪 5-HIAA urinaires 24h +++", "🧪 NSE", "🧪 NFS", "🧪 Bilan hépatique"]$$,$$["🧪 Glucagon + Insuline + Gastrine + PP (selon syndrome clinique)"]$$,'Chromogranine A = marqueur universel TNE. 5-HIAA urinaires = syndrome carcinoïde (TNE sérotonine)'),
  (56,'Tumeur Carcinoïde','Tumeur neuroendocrine (TNE)','confirmation',$$["🔬 Biopsie tumorale", "🔬 IHC : Synaptophysine +++, Chromogranine A, CD56, Ki67 (%)", "🔬 Grade OMS 2022 (G1 Ki67<3% / G2 Ki67 3-20% / G3 Ki67>20% / carcinome neuroendocrine)", "🔬 PCR MEN1 (si multiple)"]$$,$$["🔬 FISH (si carcinome neuroendocrine — TP53, RB1)"]$$,'Ki67 = facteur pronostique ET thérapeutique majeur. G1-G2 = analogues somatostatine. G3 = chimio'),
  (56,'Tumeur Carcinoïde','Tumeur neuroendocrine (TNE)','extension',$$["📡 Scintigraphie DOTATATE (Gallium-68) +++ ", "📡 Scanner TAP", "📡 Écho-endoscopie (TNE digestive)", "🧪 Chromogranine A", "🧪 5-HIAA", "🧪 NFS + Bilan hépatique"]$$,$$["📡 IRM hépatique (métas hépatiques)", "📡 PET-Scan FDG (si G3 — peu différencié)"]$$,'DOTATATE = gold standard pour TNE bien différenciées (G1-G2). FDG si G3 (peu différencié)'),
  (56,'Tumeur Carcinoïde','Tumeur neuroendocrine (TNE)','suivi',$$["🧪 Chromogranine A (tous les 3-6 mois)", "🧪 5-HIAA urinaires", "📡 Scintigraphie DOTATATE (annuelle)", "📡 Scanner TAP (tous les 6 mois)", "📡 Écho cardiaque (carcinome carcinoïde — fibrose valvulaire)"]$$,$$["📡 IRM hépatique (si métas hépatiques sous analogues)"]$$,'Écho cardiaque si syndrome carcinoïde actif — fibrose endocardique (valves droites) dans 20-50%'),
  (57,'Cancer Parathyroïde','Carcinome parathyroïdien','initial',$$["🧪 PTH (parathormone) +++", "🧪 Calcémie +++", "🧪 Phosphorémie", "🧪 Phosphatase alcaline", "🧪 NFS", "🧪 Créatinine + Clairance", "🧪 Calciurie 24h"]$$,NULL,'Hypercalcémie sévère (>3.5 mmol/L) + PTH très élevée + masse cervicale = carcinome parathyroïdien'),
  (57,'Cancer Parathyroïde','Carcinome parathyroïdien','confirmation',$$["📡 Échographie cervicale", "📡 Scintigraphie MIBI (Tc-99m séstamibi)", "🔬 Exérèse chirurgicale + examen anatomopathologique", "🔬 IHC : Parafibromine (perte = carcinome) +++, PGP9.5, MD2", "🔬 PCR CDC73/HRPT2 +++"]$$,NULL,'Parafibromine perdue = carcinome. PCR CDC73 muté dans >70% des carcinomes. Confirmation histologique post-op'),
  (57,'Cancer Parathyroïde','Carcinome parathyroïdien','extension',$$["📡 Scanner cervico-thoracique", "📡 Scintigraphie MIBI", "🧪 PTH", "🧪 Calcémie", "🧪 NFS + Bilan rénal"]$$,$$["📡 PET-Scan FDG (si récidive)", "📡 PET-Choline (meilleure sensibilité que FDG)"]$$,'Récidive locale et métas pulmonaires/osseuses tardives. PET-Choline > PET-FDG pour parathyroïde'),
  (57,'Cancer Parathyroïde','Carcinome parathyroïdien','suivi',$$["🧪 PTH (tous les 3-6 mois)", "🧪 Calcémie", "🧪 Créatinine + Clairance", "📡 Échographie cervicale (annuelle)", "📡 Scanner cervico-thoracique (annuel)"]$$,$$["📡 PET-Choline (si PTH remontante)"]$$,'PTH et calcémie = marqueurs de suivi. Récidive = hypercalcémie récurrente. Traitement hypercalcémie = urgence'),
  (58,'Cancer du Thymus','Thymome / Carcinome thymique','initial',$$["📡 Radiographie thorax (masse médiastin antérieur)", "📡 Scanner thoracique +++", "🧪 NFS", "🧪 Ac anti-récepteur acétylcholine (myasthénie)", "🧪 Ac anti-MuSK", "🧪 Bilan hépatique"]$$,NULL,'Masse médiastin antérieur + myasthénie grave = thymome jusqu''à preuve contraire'),
  (58,'Cancer du Thymus','Thymome / Carcinome thymique','confirmation',$$["📡 IRM thoracique (caractérisation)", "🔬 Biopsie (médiastinoscopie ou scanner-guidée)", "🔬 IHC : CK (AE1/AE3), p63, CD5 (carcinome thymique +), CD117 (c-KIT carcinome)", "🔬 Classification OMS (A/AB/B1/B2/B3 thymome vs carcinome)", "🔬 PCR GTF2I (thymome)"]$$,NULL,'OMS B3 et carcinome = mauvais pronostic. CD5/CD117 positifs = carcinome thymique → traitement différent'),
  (58,'Cancer du Thymus','Thymome / Carcinome thymique','extension',$$["📡 Scanner TAP (plèvre + péricarde)", "📡 PET-Scan FDG", "🧪 Ac anti-AChR + Ac anti-MuSK (myasthénie)", "🧪 Bilan auto-immun étendu (hypogammaglobulinémie, érythroblastopénie)", "🧪 NFS + Bilan complet"]$$,NULL,'Staging Masaoka-Koga OBLIGATOIRE. Bilan auto-immun complet — syndromes paranéoplasiques multiples'),
  (58,'Cancer du Thymus','Thymome / Carcinome thymique','suivi',$$["📡 Scanner thoracique (tous les 6 mois × 2 ans puis annuel)", "📡 PET-Scan (si progression)", "🧪 Ac anti-AChR (myasthénie — peut persister ou réapparaître)", "🧪 NFS + Bilan hépatique", "🧪 Bilan immunitaire (si hypogammaglobulinémie)"]$$,NULL,'Myasthénie peut persister après thymectomie — suivi neurologique obligatoire. Récidives tardives possibles (10-15 ans)');
